diffs.replacement:
{
  "name": "نظام حساب استهلاك مطاعم (CulinaTrack)",
  "description": "تطبيق متطور لحساب الاستهلاك الفعلي للخامات بناءً على الوصفات والمبيعات مع تقارير تجميعية وتفصيلية دقيقة."
}

export interface Material {
  id: string;
  name: string;
  unit: string;
}

export interface SalesItem {
  id: string;
  name: string;
}

export interface RecipeIngredient {
  materialId: string;
  quantity: number; // Quantity of material per 1 unit of sales item
}

export interface Recipe {
  itemId: string;
  ingredients: RecipeIngredient[];
}

export interface SaleEntry {
  id: string;
  itemId: string;
  quantitySold: number;
  date: string;
}

export interface AggregatedReportItem {
  materialName: string;
  unit: string;
  totalConsumption: number;
}

export interface DetailedReportItem {
  itemName: string;
  quantitySold: number;
  ingredients: {
    materialName: string;
    unit: string;
    consumedQuantity: number;
  }[];
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useEffect, useMemo } from 'react';
import { 
  LayoutDashboard, 
  ChefHat, 
  Package, 
  ShoppingCart, 
  FileText, 
  Plus, 
  Trash2, 
  Edit3, 
  ChevronRight,
  Calculator,
  Save
} from 'lucide-react';
import { 
  Material, 
  SalesItem, 
  Recipe, 
  SaleEntry, 
  AggregatedReportItem, 
  DetailedReportItem,
  RecipeIngredient
} from './types';

// Components
import Sidebar from './components/Sidebar';
import Header from './components/Header';
import MaterialsPage from './components/MaterialsPage';
import SalesItemsPage from './components/SalesItemsPage';
import RecipeBuilderPage from './components/RecipeBuilderPage';
import SalesEntryPage from './components/SalesEntryPage';
import ReportsPage from './components/ReportsPage';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'materials' | 'items' | 'recipes' | 'sales' | 'reports'>('items');

  // Simulated State (Local Storage)
  const [materials, setMaterials] = useState<Material[]>(() => {
    const saved = localStorage.getItem('materials');
    return saved ? JSON.parse(saved) : [
      { id: '1', name: 'لحم بقري', unit: 'كجم' },
      { id: '2', name: 'خبز برجر', unit: 'حبة' },
      { id: '3', name: 'دجاج', unit: 'كجم' },
      { id: '4', name: 'بطاطس', unit: 'كجم' }
    ];
  });

  const [salesItems, setSalesItems] = useState<SalesItem[]>(() => {
    const saved = localStorage.getItem('salesItems');
    return saved ? JSON.parse(saved) : [
      { id: '101', name: 'برجر كلاسيك' },
      { id: '102', name: 'ساندوتش دجاج' },
      { id: '103', name: 'وجبة بطاطس عائلية' }
    ];
  });

  const [recipes, setRecipes] = useState<Recipe[]>(() => {
    const saved = localStorage.getItem('recipes');
    return saved ? JSON.parse(saved) : [
      { itemId: '101', ingredients: [{ materialId: '1', quantity: 0.15 }, { materialId: '2', quantity: 1 }] },
      { itemId: '102', ingredients: [{ materialId: '3', quantity: 0.2 }, { materialId: '2', quantity: 1 }] },
      { itemId: '103', ingredients: [{ materialId: '4', quantity: 0.5 }] }
    ];
  });

  const [sales, setSales] = useState<SaleEntry[]>(() => {
    const saved = localStorage.getItem('sales');
    return saved ? JSON.parse(saved) : [];
  });

  // Sync to local storage
  useEffect(() => {
    localStorage.setItem('materials', JSON.stringify(materials));
    localStorage.setItem('salesItems', JSON.stringify(salesItems));
    localStorage.setItem('recipes', JSON.stringify(recipes));
    localStorage.setItem('sales', JSON.stringify(sales));
  }, [materials, salesItems, recipes, sales]);

  const renderContent = () => {
    switch (activeTab) {
      case 'materials':
        return <MaterialsPage materials={materials} setMaterials={setMaterials} />;
      case 'items':
        return <SalesItemsPage items={salesItems} setItems={setSalesItems} />;
      case 'recipes':
        return <RecipeBuilderPage items={salesItems} materials={materials} recipes={recipes} setRecipes={setRecipes} />;
      case 'sales':
        return <SalesEntryPage items={salesItems} sales={sales} setSales={setSales} />;
      case 'reports':
        return <ReportsPage materials={materials} items={salesItems} recipes={recipes} sales={sales} />;
      default:
        return <SalesItemsPage items={salesItems} setItems={setSalesItems} />;
    }
  };

  return (
    <div className="flex min-h-screen bg-slate-50 text-slate-900" dir="rtl">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />
      <div className="flex-1 flex flex-col">
        <Header activeTab={activeTab} />
        <main className="p-4 md:p-8 flex-1 overflow-y-auto">
          {renderContent()}
        </main>
      </div>
    </div>
  );
};

export default App;

import React from 'react';
import { Package, ChefHat, ShoppingCart, FileText, LayoutDashboard, UtensilsCrossed } from 'lucide-react';

interface SidebarProps {
  activeTab: string;
  setActiveTab: (tab: any) => void;
