import React, { useState } from 'react';
import { Plus, Trash2, Package } from 'lucide-react';
import { Material } from '../types';

interface Props {
  materials: Material[];
  setMaterials: React.Dispatch<React.SetStateAction<Material[]>>;
}

const MaterialsPage: React.FC<Props> = ({ materials, setMaterials }) => {
  const [name, setName] = useState('');
  const [unit, setUnit] = useState('كجم');

  const addMaterial = (e: React.FormEvent) => {
    e.preventDefault();
    if (!name) return;
    const newMaterial: Material = {
      id: Date.now().toString(),
      name,
      unit
    };
    setMaterials([...materials, newMaterial]);
    setName('');
  };

  const deleteMaterial = (id: string) => {
    setMaterials(materials.filter(m => m.id !== id));
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6">
      <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
        <h3 className="text-lg font-semibold mb-4 flex items-center gap-2">
          <Plus className="w-5 h-5 text-emerald-500" />
          إضافة خامة جديدة
        </h3>
        <form onSubmit={addMaterial} className="flex flex-col md:flex-row gap-4">
          <input
            type="text"
            placeholder="اسم الخامة (مثال: لحم بقري)"
            className="flex-1 border border-slate-200 rounded-xl px-4 py-2 focus:ring-2 focus:ring-emerald-500 outline-none"
            value={name}
            onChange={(e) => setName(e.target.value)}
          />
          <select
            className="border border-slate-200 rounded-xl px-4 py-2 bg-white outline-none"
            value={unit}
            onChange={(e) => setUnit(e.target.value)}
          >
            <option value="كجم">كجم</option>
            <option value="جرام">جرام</option>
            <option value="لتر">لتر</option>
            <option value="حبة">حبة</option>
            <option value="كرتون">كرتون</option>
          </select>
          <button className="bg-emerald-500 text-white px-6 py-2 rounded-xl hover:bg-emerald-600 transition-colors">
            إضافة
          </button>
        </form>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
        <table className="w-full text-right">
          <thead className="bg-slate-50 border-b border-slate-200">
            <tr>
              <th className="px-6 py-4 font-semibold text-slate-600">اسم الخامة</th>
              <th className="px-6 py-4 font-semibold text-slate-600">وحدة القياس</th>
              <th className="px-6 py-4 font-semibold text-slate-600 w-24">إجراءات</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {materials.map((m) => (
              <tr key={m.id} className="hover:bg-slate-50 transition-colors">
                <td className="px-6 py-4 flex items-center gap-3">
                  <Package className="w-4 h-4 text-slate-400" />
                  {m.name}
                </td>
                <td className="px-6 py-4">{m.unit}</td>
                <td className="px-6 py-4">
                  <button 
                    onClick={() => deleteMaterial(m.id)}
                    className="p-2 text-rose-500 hover:bg-rose-50 rounded-lg transition-colors"
                  >
                    <Trash2 className="w-4 h-4" />
                  </button>
                </td>
              </tr>
            ))}
