import React, { useState } from 'react';
import { Save, Plus, Trash2, Calculator } from 'lucide-react';
import { SalesItem, Material, Recipe, RecipeIngredient } from '../types';

interface Props {
  items: SalesItem[];
  materials: Material[];
  recipes: Recipe[];
  setRecipes: React.Dispatch<React.SetStateAction<Recipe[]>>;
}

const RecipeBuilderPage: React.FC<Props> = ({ items, materials, recipes, setRecipes }) => {
  const [selectedItemId, setSelectedItemId] = useState<string>('');

  const currentRecipe = recipes.find(r => r.itemId === selectedItemId) || {
    itemId: selectedItemId,
    ingredients: []
  };

  const addIngredient = () => {
    if (!selectedItemId) return;
    const updatedRecipes = [...recipes];
    const index = updatedRecipes.findIndex(r => r.itemId === selectedItemId);

    const newIngredient: RecipeIngredient = {
      materialId: materials[0]?.id || '',
      quantity: 0
    };

    if (index > -1) {
      updatedRecipes[index].ingredients.push(newIngredient);
    } else {
      updatedRecipes.push({
        itemId: selectedItemId,
        ingredients: [newIngredient]
      });
    }
    setRecipes(updatedRecipes);
  };

  const updateIngredient = (idx: number, field: keyof RecipeIngredient, value: string | number) => {
    const updatedRecipes = [...recipes];
    const index = updatedRecipes.findIndex(r => r.itemId === selectedItemId);
    if (index > -1) {
      const ingredient = updatedRecipes[index].ingredients[idx];
      if (field === 'quantity') {
        ingredient.quantity = Number(value);
      } else {
        ingredient.materialId = String(value);
      }
      setRecipes(updatedRecipes);
    }
  };

  const removeIngredient = (idx: number) => {
    const updatedRecipes = [...recipes];
    const index = updatedRecipes.findIndex(r => r.itemId === selectedItemId);
    if (index > -1) {
      updatedRecipes[index].ingredients.splice(idx, 1);
      setRecipes(updatedRecipes);
    }
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6">
      <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
        <label className="block text-sm font-semibold text-slate-700 mb-2">اختر صنف المبيعات لتعديل وصفته:</label>
        <select
          className="w-full border border-slate-200 rounded-xl px-4 py-3 bg-white outline-none focus:ring-2 focus:ring-emerald-500"
          value={selectedItemId}
          onChange={(e) => setSelectedItemId(e.target.value)}
        >
          <option value="">-- اختر صنفاً --</option>
          {items.map(i => (
            <option key={i.id} value={i.id}>{i.name}</option>
          ))}
        </select>
      </div>

      {selectedItemId && (
        <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden animate-in fade-in slide-in-from-bottom-2">
          <div className="p-6 border-b border-slate-100 flex justify-between items-center">
            <h3 className="font-bold text-slate-800">مكونات الوصفة: {items.find(i => i.id === selectedItemId)?.name}</h3>
            <button 
              onClick={addIngredient}
              className="flex items-center gap-2 text-sm bg-emerald-500 text-white px-4 py-2 rounded-xl hover:bg-emerald-600 transition-colors"
            >
              <Plus className="w-4 h-4" /> إضافة خامة
            </button>
          </div>
          <div className="p-6">
            {currentRecipe.ingredients.length === 0 ? (
              <div className="text-center py-12 text-slate-400">
                <Calculator className="w-12 h-12 mx-auto mb-3 opacity-20" />
                <p>لا توجد خامات مضافة لهذه الوصفة بعد.</p>
              </div>
            ) : (
              <div className="space-y-4">
                {currentRecipe.ingredients.map((ing, idx) => (
                  <div key={idx} className="flex gap-4 items-end">
                    <div className="flex-1">
                      <label className="block text-xs text-slate-500 mb-1 mr-1">الخامة</label>
                      <select
                        className="w-full border border-slate-200 rounded-xl px-4 py-2 bg-slate-50 outline-none"
                        value={ing.materialId}
                        onChange={(e) => updateIngredient(idx, 'materialId', e.target.value)}
                      >
                        {materials.map(m => (
                          <option key={m.id} value={m.id}>{m.name} ({m.unit})</option>
                        ))}
                      </select>
                    </div>
                    <div className="w-48">
                      <label className="block text-xs text-slate-500 mb-1 mr-1">الكمية لكل وحدة مباعة</label>
                      <input
                        type="number"
                        step="0.001"
                        className="w-full border border-slate-200 rounded-xl px-4 py-2 outline-none"
                        value={ing.quantity}
                        onChange={(e) => updateIngredient(idx, 'quantity', e.target.value)}
                      />
                    </div>
                    <button 
                      onClick={() => removeIngredient(idx)}
                      className="p-2.5 text-rose-500 hover:bg-rose-50 rounded-xl"
                    >
                      <Trash2 className="w-5 h-5" />
                    </button>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default RecipeBuilderPage;

import React, { useState } from 'react';
import { Save, History, ShoppingCart } from 'lucide-react';
import { SalesItem, SaleEntry } from '../types';

interface Props {
  items: SalesItem[];
  sales: SaleEntry[];
  setSales: React.Dispatch<React.SetStateAction<SaleEntry[]>>;
}

const SalesEntryPage: React.FC<Props> = ({ items, sales, setSales }) => {
  const [quantities, setQuantities] = useState<Record<string, number>>({});
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);

  const handleSave = () => {
    const newSales: SaleEntry[] = Object.entries(quantities)
      .filter(([_, qty]) => qty > 0)
      .map(([itemId, qty]) => ({
        id: Math.random().toString(36).substr(2, 9),
        itemId,
        quantitySold: qty,
        date
      }));

    setSales([...sales, ...newSales]);
    setQuantities({});
    alert('تم حفظ المبيعات بنجاح!');
  };

  const handleQtyChange = (itemId: string, val: string) => {
    setQuantities(prev => ({
      ...prev,
      [itemId]: parseInt(val) || 0
    }));
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6">
      <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h3 className="text-lg font-bold text-slate-800">إدخال مبيعات اليوم</h3>
          <p className="text-sm text-slate-500">أدخل عدد الوحدات المباعة من كل صنف</p>
        </div>
        <input 
          type="date" 
          className="border border-slate-200 rounded-xl px-4 py-2 outline-none"
          value={date}
          onChange={(e) => setDate(e.target.value)}
        />
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
        <table className="w-full text-right">
          <thead className="bg-slate-50 border-b border-slate-200">
            <tr>
              <th className="px-6 py-4 font-semibold text-slate-600">اسم الصنف</th>
              <th className="px-6 py-4 font-semibold text-slate-600 w-48 text-center">الكمية المباعة</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {items.map((item) => (
              <tr key={item.id} className="hover:bg-slate-50 transition-colors">
                <td className="px-6 py-4 font-medium text-slate-700">{item.name}</td>
                <td className="px-6 py-4">
                  <input
                    type="number"
                    min="0"
                    placeholder="0"
                    className="w-full text-center border border-slate-200 rounded-xl px-4 py-2 outline-none focus:ring-2 focus:ring-emerald-500"
                    value={quantities[item.id] || ''}
                    onChange={(e) => handleQtyChange(item.id, e.target.value)}
                  />
                </td>
              </tr>
            ))}
          </tbody>
        </table>
        <div className="p-6 bg-slate-50 border-t border-slate-200 flex justify-end">
          <button 
            onClick={handleSave}
            disabled={Object.values(quantities).every(q => q <= 0)}
            className="flex items-center gap-2 bg-emerald-500 text-white px-8 py-3 rounded-xl font-bold hover:bg-emerald-600 disabled:bg-slate-300 disabled:cursor-not-allowed transition-all"
          >
            <Save className="w-5 h-5" /> حفظ المبيعات
          </button>
        </div>
      </div>

      <div className="mt-12">
        <h4 className="text-sm font-bold text-slate-400 uppercase tracking-wider mb-4 flex items-center gap-2">
          <History className="w-4 h-4" /> سجل المبيعات الأخيرة
        </h4>
        <div className="space-y-2">
