    // Cast Object.entries to ensure type safety for quantities and resolve 'unknown' type errors
    const entries = Object.entries(quantities) as [string, number][];
    const newSales: SaleEntry[] = entries
      .filter(([_, qty]) => qty > 0)
      .map(([itemId, qty]) => ({
        id: Math.random().toString(36).substr(2, 9),
        itemId,
        quantitySold: qty,
        date
      }));

    setSales([...sales, ...newSales]);
    setQuantities({});
    alert('تم حفظ المبيعات بنجاح!');
  };

  const handleQtyChange = (itemId: string, val: string) => {
    setQuantities(prev => ({
      ...prev,
