import React, { useState } from 'react';
import { Save, History, ShoppingCart, AlertCircle } from 'lucide-react';
import { SalesItem, SaleEntry } from '../types';

interface Props {
  items: SalesItem[];
  sales: SaleEntry[];
  setSales: React.Dispatch<React.SetStateAction<SaleEntry[]>>;
}

const SalesEntryPage: React.FC<Props> = ({ items, sales, setSales }) => {
  const [quantities, setQuantities] = useState<Record<string, number>>({});
  const [date, setDate] = useState<string>(new Date().toISOString().split('T')[0]);

  const handleSave = () => {
    const entries = Object.entries(quantities) as [string, number][];
    const validEntries = entries.filter(([_, qty]) => qty > 0);

    if (validEntries.length === 0) {
      alert('يرجى إدخال كمية مباعة لواحد على الأقل من الأصناف');
      return;
    }

    const newSales: SaleEntry[] = validEntries.map(([itemId, qty]) => ({
        id: Math.random().toString(36).substr(2, 9),
        itemId,
        quantitySold: qty,
        date
      }));

    setSales([...sales, ...newSales]);
    setQuantities({});
    alert('تم حفظ المبيعات بنجاح!');
  };

  const handleQtyChange = (itemId: string, val: string) => {
    const num = parseInt(val);
    setQuantities(prev => ({
      ...prev,
      [itemId]: isNaN(num) ? 0 : Math.max(0, num)
    }));
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6">
      <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h3 className="text-lg font-bold text-slate-800">إدخال مبيعات اليوم</h3>
          <p className="text-sm text-slate-500">أدخل عدد الوحدات المباعة من كل صنف</p>
        </div>
        <div className="flex items-center gap-3">
          <label className="text-sm font-bold text-slate-600">التاريخ:</label>
          <input 
            type="date" 
            className="border border-slate-200 rounded-xl px-4 py-2 outline-none focus:ring-2 focus:ring-emerald-500 transition-all font-medium"
            value={date}
            onChange={(e) => setDate(e.target.value)}
          />
        </div>
      </div>

      {items.length === 0 ? (
        <div className="bg-white p-12 text-center rounded-2xl border border-slate-200">
          <AlertCircle className="w-12 h-12 mx-auto mb-4 text-slate-300" />
          <p className="text-slate-500 font-bold">لا توجد أصناف مبيعات مضافة في النظام.</p>
          <p className="text-slate-400 text-sm mt-1">قم بإضافة الأصناف من صفحة "أصناف المبيعات".</p>
        </div>
      ) : (
        <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
          <table className="w-full text-right">
            <thead className="bg-slate-50 border-b border-slate-200">
              <tr>
                <th className="px-6 py-4 font-semibold text-slate-600">اسم الصنف</th>
                <th className="px-6 py-4 font-semibold text-slate-600 w-48 text-center">الكمية المباعة</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {items.map((item) => (
                <tr key={item.id} className="hover:bg-slate-50 transition-colors">
                  <td className="px-6 py-4 font-medium text-slate-700">{item.name}</td>
                  <td className="px-6 py-4">
                    <input
                      type="number"
                      min="0"
                      placeholder="0"
                      className="w-full text-center border border-slate-200 rounded-xl px-4 py-2 outline-none focus:ring-2 focus:ring-emerald-500 transition-all font-mono font-bold"
                      value={quantities[item.id] || ''}
                      onChange={(e) => handleQtyChange(item.id, e.target.value)}
                    />
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
          <div className="p-6 bg-slate-50 border-t border-slate-200 flex justify-end">
            <button 
              onClick={handleSave}
              disabled={(Object.values(quantities) as number[]).every(q => q <= 0)}
              className="flex items-center gap-2 bg-emerald-500 text-white px-8 py-3 rounded-xl font-bold hover:bg-emerald-600 disabled:bg-slate-300 disabled:cursor-not-allowed transition-all shadow-lg shadow-emerald-500/20"
            >
              <Save className="w-5 h-5" /> حفظ المبيعات
            </button>
          </div>
        </div>
      )}

      {sales.length > 0 && (
        <div className="mt-12">
          <h4 className="text-sm font-bold text-slate-400 uppercase tracking-wider mb-4 flex items-center gap-2">
            <History className="w-4 h-4" /> سجل المبيعات الأخيرة
          </h4>
          <div className="space-y-2">
            {sales.slice(-5).reverse().map(s => (
              <div key={s.id} className="bg-white p-4 rounded-xl border border-slate-100 flex justify-between items-center text-sm shadow-sm">
                <span className="font-bold text-slate-700">{items.find(i => i.id === s.itemId)?.name}</span>
                <span className="text-emerald-600 bg-emerald-50 px-3 py-1 rounded-full font-bold">{s.quantitySold} وحدة</span>
                <span className="text-slate-400 font-mono">{s.date}</span>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

