import React, { useState } from 'react';
import { Plus, Trash2, Package, AlertCircle, Edit3, Save, X } from 'lucide-react';
import { Material } from '../types';

interface Props {
  materials: Material[];
  setMaterials: React.Dispatch<React.SetStateAction<Material[]>>;
}

const MaterialsPage: React.FC<Props> = ({ materials, setMaterials }) => {
  const [name, setName] = useState('');
  const [unit, setUnit] = useState('كجم');
  const [error, setError] = useState('');

  // State for editing
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editName, setEditName] = useState('');
  const [editUnit, setEditUnit] = useState('');
  const [editError, setEditError] = useState('');

  const addMaterial = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (!name.trim()) {
      setError('يرجى إدخال اسم الخامة');
      return;
    }

    if (materials.some(m => m.name.trim().toLowerCase() === name.trim().toLowerCase())) {
      setError('هذه الخامة موجودة بالفعل');
      return;
    }

    const newMaterial: Material = {
      id: Date.now().toString(),
      name: name.trim(),
      unit
    };
    setMaterials([...materials, newMaterial]);
    setName('');
  };

  const startEditing = (m: Material) => {
    setEditingId(m.id);
    setEditName(m.name);
    setEditUnit(m.unit);
    setEditError('');
  };

  const cancelEditing = () => {
    setEditingId(null);
  };

  const saveEdit = (id: string) => {
    if (!editName.trim()) {
      setEditError('الاسم لا يمكن أن يكون فارغاً');
      return;
    }

    // Check duplication excluding itself
    if (materials.some(m => m.id !== id && m.name.trim().toLowerCase() === editName.trim().toLowerCase())) {
      setEditError('هذا الاسم مستخدم لخامة أخرى');
      return;
    }

    setMaterials(materials.map(m => 
      m.id === id ? { ...m, name: editName.trim(), unit: editUnit } : m
    ));
    setEditingId(null);
  };

  const deleteMaterial = (id: string) => {
    if (confirm('هل أنت متأكد من حذف هذه الخامة؟ قد يؤثر ذلك على الوصفات الحالية.')) {
      setMaterials(materials.filter(m => m.id !== id));
    }
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6">
      <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
        <h3 className="text-lg font-semibold mb-4 flex items-center gap-2">
          <Plus className="w-5 h-5 text-emerald-500" />
          إضافة خامة جديدة
        </h3>
        <form onSubmit={addMaterial} className="space-y-4">
          <div className="flex flex-col md:flex-row gap-4">
            <div className="flex-1">
              <input
                type="text"
                placeholder="اسم الخامة (مثال: لحم بقري)"
                className={`w-full border ${error ? 'border-rose-500' : 'border-slate-200'} rounded-xl px-4 py-2 focus:ring-2 focus:ring-emerald-500 outline-none transition-all`}
                value={name}
                onChange={(e) => {
                  setName(e.target.value);
                  if (error) setError('');
                }}
              />
              {error && (
                <p className="text-rose-500 text-xs mt-1 flex items-center gap-1">
                  <AlertCircle className="w-3 h-3" /> {error}
                </p>
              )}
            </div>
            <select
              className="border border-slate-200 rounded-xl px-4 py-2 bg-white outline-none"
              value={unit}
              onChange={(e) => setUnit(e.target.value)}
            >
              <option value="كجم">كجم</option>
              <option value="جرام">جرام</option>
              <option value="لتر">لتر</option>
              <option value="حبة">حبة</option>
              <option value="كرتون">كرتون</option>
            </select>
            <button className="bg-emerald-500 text-white px-6 py-2 rounded-xl hover:bg-emerald-600 transition-colors font-bold">
              إضافة
            </button>
          </div>
        </form>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
        <table className="w-full text-right">
          <thead className="bg-slate-50 border-b border-slate-200">
            <tr>
