      id: Math.random().toString(36).substr(2, 9),
      itemId,
      quantitySold: qty,
      date
    }));

    await onSave(newSales);
    setQuantities({});
    setIsSaving(false);
    alert('تم حفظ المبيعات بنجاح!');
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6">
      <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div><h3 className="text-lg font-bold text-slate-800">إدخال مبيعات اليوم</h3><p className="text-sm text-slate-500">أدخل عدد الوحدات المباعة من كل صنف</p></div>
        <input type="date" className="border rounded-xl px-4 py-2 outline-none focus:ring-2 focus:ring-emerald-500 font-medium" value={date} onChange={(e) => setDate(e.target.value)} />
