      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
        <table className="w-full text-right">
          <thead className="bg-slate-50 border-b border-slate-200 text-slate-600">
            <tr><th className="px-6 py-4 font-semibold">اسم الصنف</th><th className="px-6 py-4 font-semibold w-48 text-center">الكمية المباعة</th></tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {items.map((item) => (
              <tr key={item.id} className="hover:bg-slate-50 transition-colors">
                <td className="px-6 py-4 font-medium text-slate-700">{item.name}</td>
                <td className="px-6 py-4">
                  <input type="number" min="0" placeholder="0" className="w-full text-center border rounded-xl px-4 py-2 font-mono font-bold outline-none focus:ring-2 focus:ring-emerald-500" value={quantities[item.id] || ''} onChange={(e) => setQuantities({...quantities, [item.id]: parseInt(e.target.value) || 0})} />
