              </tr>
            ))}
          </tbody>
        </table>
        <div className="p-6 bg-slate-50 border-t flex justify-end">
          <button onClick={handleSave} disabled={isSaving || Object.values(quantities).every(q => q <= 0)} className="flex items-center gap-2 bg-emerald-500 text-white px-8 py-3 rounded-xl font-bold shadow-lg shadow-emerald-500/20 disabled:bg-slate-300">
            {isSaving ? <Loader2 className="w-5 h-5 animate-spin" /> : <Save className="w-5 h-5" />} حفظ المبيعات
          </button>
        </div>
      </div>
    </div>
  );
};

