export default MaterialsPage;

import React, { useState } from 'react';
import { Plus, Trash2, Utensils, AlertCircle, Edit3, Save, X } from 'lucide-react';
import { SalesItem } from '../types';

interface Props {
  items: SalesItem[];
  onAdd: (i: SalesItem) => Promise<void>;
  onUpdate: (i: SalesItem) => Promise<void>;
  onDelete: (id: string) => Promise<void>;
}

const SalesItemsPage: React.FC<Props> = ({ items, onAdd, onUpdate, onDelete }) => {
  const [name, setName] = useState('');
  const [error, setError] = useState('');
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editName, setEditName] = useState('');

  const addItem = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!name.trim()) return setError('يرجى إدخال اسم الصنف');
    if (items.some(i => i.name.trim().toLowerCase() === name.trim().toLowerCase())) return setError('هذا الصنف موجود بالفعل');

    await onAdd({ id: crypto.randomUUID(), name: name.trim() });
    setName('');
    setError('');
  };

  const saveEdit = async (id: string) => {
    if (!editName.trim()) return;
    await onUpdate({ id, name: editName.trim() });
    setEditingId(null);
  };

  const handleDelete = async (id: string, name: string) => {
    if (window.confirm(`هل أنت متأكد من حذف الصنف "${name}"؟ سيؤدي ذلك إلى حذف الوصفة المرتبطة به وسجل مبيعاته نهائياً.`)) {
      await onDelete(id);
    }
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6">
      <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
        <h3 className="text-lg font-semibold mb-4 flex items-center gap-2">
          <Plus className="w-5 h-5 text-emerald-500" /> إضافة صنف مبيعات جديد
        </h3>
        <form onSubmit={addItem} className="flex gap-4">
          <div className="flex-1">
            <input
              type="text" placeholder="اسم الصنف (مثال: برجر كلاسيك)"
              className="w-full border border-slate-200 rounded-xl px-4 py-2 outline-none focus:ring-2 focus:ring-emerald-500"
              value={name} onChange={(e) => setName(e.target.value)}
            />
            {error && <p className="text-rose-500 text-xs mt-1">{error}</p>}
          </div>
          <button className="bg-emerald-500 text-white px-6 py-2 rounded-xl hover:bg-emerald-600 font-bold h-fit">إضافة</button>
        </form>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
        <table className="w-full text-right">
          <thead className="bg-slate-50 border-b border-slate-200 text-slate-600">
            <tr><th className="px-6 py-4 font-semibold">اسم الصنف</th><th className="px-6 py-4 font-semibold w-32">إجراءات</th></tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {items.map((item) => (
              <tr key={item.id} className="hover:bg-slate-50 transition-colors">
                {editingId === item.id ? (
                  <>
                    <td className="px-6 py-3">
                      <input type="text" className="w-full border rounded-lg px-3 py-1 outline-none focus:ring-2 focus:ring-emerald-500" value={editName} onChange={(e) => setEditName(e.target.value)} autoFocus />
                    </td>
                    <td className="px-6 py-3 flex gap-2">
                      <button onClick={() => saveEdit(item.id)} className="p-1.5 text-emerald-600 hover:bg-emerald-50 rounded-lg"><Save className="w-4 h-4" /></button>
                      <button onClick={() => setEditingId(null)} className="p-1.5 text-slate-400 hover:bg-slate-100 rounded-lg"><X className="w-4 h-4" /></button>
                    </td>
                  </>
                ) : (
                  <>
                    <td className="px-6 py-4 flex items-center gap-3"><Utensils className="w-4 h-4 text-slate-400" />{item.name}</td>
                    <td className="px-6 py-4 flex gap-1">
                      <button onClick={() => { setEditingId(item.id); setEditName(item.name); }} className="p-2 text-blue-500 hover:bg-blue-50 rounded-lg" title="تعديل"><Edit3 className="w-4 h-4" /></button>
                      <button onClick={() => handleDelete(item.id, item.name)} className="p-2 text-rose-500 hover:bg-rose-50 rounded-lg" title="حذف"><Trash2 className="w-4 h-4" /></button>
                    </td>
                  </>
                )}
              </tr>
            ))}
            {items.length === 0 && (
              <tr>
                <td colSpan={2} className="px-6 py-8 text-center text-slate-400">لا توجد أصناف مبيعات مضافة</td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default SalesItemsPage;

import React, { useState, useEffect } from 'react';
import { ChefHat, Loader2 } from 'lucide-react';
import { 
  Material, 
  SalesItem, 
  Recipe, 
  SaleEntry 
} from './types';
import { db, initDb } from './db';

// Components
import Sidebar from './components/Sidebar';
import Header from './components/Header';
import MaterialsPage from './components/MaterialsPage';
import SalesItemsPage from './components/SalesItemsPage';
import RecipeBuilderPage from './components/RecipeBuilderPage';
import SalesEntryPage from './components/SalesEntryPage';
import ReportsPage from './components/ReportsPage';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'materials' | 'items' | 'recipes' | 'sales' | 'reports'>('items');
  const [isLoading, setIsLoading] = useState(true);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  const [materials, setMaterials] = useState<Material[]>([]);
  const [salesItems, setSalesItems] = useState<SalesItem[]>([]);
  const [recipes, setRecipes] = useState<Recipe[]>([]);
  const [sales, setSales] = useState<SaleEntry[]>([]);

  // Initial Load
  useEffect(() => {
    const loadData = async () => {
      try {
        await initDb();
        const [mats, items, recs, sls] = await Promise.all([
          db.getMaterials(),
          db.getItems(),
          db.getRecipes(),
          db.getSales()
        ]);
        setMaterials(mats);
        setSalesItems(items);
        setRecipes(recs);
        setSales(sls);
      } catch (error) {
        console.error("Error loading data from Turso:", error);
        alert("حدث خطأ أثناء الاتصال بقاعدة البيانات.");
      } finally {
        setIsLoading(false);
      }
    };
    loadData();
  }, []);

  const handleAddMaterial = async (m: Material) => {
    await db.saveMaterial(m);
    setMaterials(prev => [...prev, m]);
  };

  const handleUpdateMaterial = async (updated: Material) => {
    await db.saveMaterial(updated);
    setMaterials(prev => prev.map(m => m.id === updated.id ? updated : m));
  };

  const handleDeleteMaterial = async (id: string) => {
    await db.deleteMaterial(id);
    setMaterials(prev => prev.filter(m => m.id !== id));
  };

  const handleAddItem = async (item: SalesItem) => {
    await db.saveItem(item);
    setSalesItems(prev => [...prev, item]);
  };

  const handleUpdateItem = async (updated: SalesItem) => {
    await db.saveItem(updated);
    setSalesItems(prev => prev.map(i => i.id === updated.id ? updated : i));
  };

  const handleDeleteItem = async (id: string) => {
    await db.deleteItem(id);
    setSalesItems(prev => prev.filter(i => i.id !== id));
    setRecipes(prev => prev.filter(r => r.itemId !== id));
  };

  const handleSaveRecipe = async (recipe: Recipe) => {
    await db.saveRecipe(recipe);
    setRecipes(prev => {
      const exists = prev.some(r => r.itemId === recipe.itemId);
      if (exists) return prev.map(r => r.itemId === recipe.itemId ? recipe : r);
      return [...prev, recipe];
    });
  };

  const handleSaveSales = async (newSales: SaleEntry[]) => {
    await db.saveSales(newSales);
    setSales(prev => [...prev, ...newSales]);
  };

  if (isLoading) {
    return (
      <div className="min-h-screen bg-slate-900 flex flex-col items-center justify-center text-white space-y-4">
        <ChefHat className="w-16 h-16 text-emerald-500 animate-bounce" />
        <div className="flex items-center gap-2 text-xl font-bold">
          <Loader2 className="w-6 h-6 animate-spin text-emerald-500" />
          جاري الاتصال بقاعدة بيانات Turso...
        </div>
      </div>
    );
  }

  const renderContent = () => {
    switch (activeTab) {
      case 'materials':
        return (
          <MaterialsPage 
            materials={materials} 
            onAdd={handleAddMaterial} 
            onUpdate={handleUpdateMaterial} 
            onDelete={handleDeleteMaterial} 
          />
        );
      case 'items':
        return (
          <SalesItemsPage 
            items={salesItems} 
            onAdd={handleAddItem} 
            onUpdate={handleUpdateItem} 
            onDelete={handleDeleteItem} 
          />
        );
      case 'recipes':
        return (
          <RecipeBuilderPage 
            items={salesItems} 
            materials={materials} 
            recipes={recipes} 
            onSave={handleSaveRecipe} 
          />
        );
      case 'sales':
        return (
          <SalesEntryPage 
            items={salesItems} 
            sales={sales} 
            onSave={handleSaveSales} 
          />
        );
      case 'reports':
        return (
          <ReportsPage 
            materials={materials} 
            items={salesItems} 
            recipes={recipes} 
            sales={sales} 
          />
        );
      default:
        return null;
    }
  };

  return (
    <div className="flex min-h-screen bg-slate-50 text-slate-900" dir="rtl">
      <Sidebar 
        activeTab={activeTab} 
        setActiveTab={setActiveTab} 
        isOpen={isSidebarOpen} 
        setIsOpen={setIsSidebarOpen} 
      />
      <div className="flex-1 flex flex-col min-w-0">
        <Header 
          activeTab={activeTab} 
          onOpenSidebar={() => setIsSidebarOpen(true)} 
        />
        <main className="p-4 md:p-8 flex-1 overflow-y-auto">
          {renderContent()}
        </main>
      </div>
    </div>
  );
};

export default App;

