export const db = {
  // Materials
  getMaterials: async (): Promise<Material[]> => {
    const rs = await client.execute("SELECT * FROM materials ORDER BY name");
    return rs.rows as unknown as Material[];
  },
  saveMaterial: async (m: Material) => {
    await client.execute({
      sql: "INSERT OR REPLACE INTO materials (id, name, unit) VALUES (?, ?, ?)",
      args: [m.id, m.name, m.unit]
    });
  },
  deleteMaterial: async (id: string) => {
    await client.execute({ sql: "DELETE FROM materials WHERE id = ?", args: [id] });
  },

  // Sales Items
  getItems: async (): Promise<SalesItem[]> => {
    const rs = await client.execute("SELECT * FROM sales_items ORDER BY name");
    return rs.rows as unknown as SalesItem[];
  },
  saveItem: async (i: SalesItem) => {
    await client.execute({
      sql: "INSERT OR REPLACE INTO sales_items (id, name) VALUES (?, ?)",
      args: [i.id, i.name]
    });
  },
  deleteItem: async (id: string) => {
    await client.batch([
      { sql: "DELETE FROM sales_items WHERE id = ?", args: [id] },
      { sql: "DELETE FROM recipes WHERE item_id = ?", args: [id] }
    ], "write");
  },

  // Recipes
  getRecipes: async (): Promise<Recipe[]> => {
    const rs = await client.execute("SELECT * FROM recipes");
    const grouped: Record<string, Recipe> = {};
    rs.rows.forEach(row => {
      const itemId = row.item_id as string;
      if (!grouped[itemId]) grouped[itemId] = { itemId, ingredients: [] };
      grouped[itemId].ingredients.push({
        materialId: row.material_id as string,
        quantity: row.quantity as number
      });
    });
    return Object.values(grouped);
  },
  saveRecipe: async (recipe: Recipe) => {
    const queries = [
      { sql: "DELETE FROM recipes WHERE item_id = ?", args: [recipe.itemId] },
      ...recipe.ingredients.map(ing => ({
        sql: "INSERT INTO recipes (item_id, material_id, quantity) VALUES (?, ?, ?)",
        args: [recipe.itemId, ing.materialId, ing.quantity]
      }))
    ];
    await client.batch(queries, "write");
  },

  // Sales
  getSales: async (): Promise<SaleEntry[]> => {
    const rs = await client.execute("SELECT id, item_id as itemId, quantity_sold as quantitySold, sale_date as date FROM sales ORDER BY sale_date DESC");
    return rs.rows as unknown as SaleEntry[];
  },
  saveSales: async (newSales: SaleEntry[]) => {
    const queries = newSales.map(s => ({
      sql: "INSERT INTO sales (id, item_id, quantity_sold, sale_date) VALUES (?, ?, ?, ?)",
      args: [s.id, s.itemId, s.quantitySold, s.date]
    }));
    await client.batch(queries, "write");
  },
  deleteSale: async (id: string) => {
    await client.execute({ sql: "DELETE FROM sales WHERE id = ?", args: [id] });
  },
  updateSale: async (id: string, quantity: number) => {
    await client.execute({
      sql: "UPDATE sales SET quantity_sold = ? WHERE id = ?",
      args: [quantity, id]
    });
  }
};

import React, { useState, useEffect } from 'react';
import { ChefHat, Loader2 } from 'lucide-react';
import { 
  Material, 
  SalesItem, 
  Recipe, 
  SaleEntry 
} from './types';
import { db, initDb } from './db';

// Components
import Sidebar from './components/Sidebar';
import Header from './components/Header';
import MaterialsPage from './components/MaterialsPage';
import SalesItemsPage from './components/SalesItemsPage';
import RecipeBuilderPage from './components/RecipeBuilderPage';
import SalesEntryPage from './components/SalesEntryPage';
import ReportsPage from './components/ReportsPage';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'materials' | 'items' | 'recipes' | 'sales' | 'reports'>('items');
  const [isLoading, setIsLoading] = useState(true);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  const [materials, setMaterials] = useState<Material[]>([]);
  const [salesItems, setSalesItems] = useState<SalesItem[]>([]);
  const [recipes, setRecipes] = useState<Recipe[]>([]);
  const [sales, setSales] = useState<SaleEntry[]>([]);

  // Initial Load
  useEffect(() => {
    const loadData = async () => {
      try {
        await initDb();
        const [mats, items, recs, sls] = await Promise.all([
          db.getMaterials(),
          db.getItems(),
          db.getRecipes(),
          db.getSales()
        ]);
        setMaterials(mats);
        setSalesItems(items);
        setRecipes(recs);
        setSales(sls);
      } catch (error) {
        console.error("Error loading data from Turso:", error);
        alert("حدث خطأ أثناء الاتصال بقاعدة البيانات.");
      } finally {
        setIsLoading(false);
      }
    };
    loadData();
  }, []);

  const handleAddMaterial = async (m: Material) => {
    await db.saveMaterial(m);
    setMaterials(prev => [...prev, m]);
  };

  const handleUpdateMaterial = async (updated: Material) => {
    await db.saveMaterial(updated);
    setMaterials(prev => prev.map(m => m.id === updated.id ? updated : m));
  };

  const handleDeleteMaterial = async (id: string) => {
    await db.deleteMaterial(id);
    setMaterials(prev => prev.filter(m => m.id !== id));
  };

  const handleAddItem = async (item: SalesItem) => {
    await db.saveItem(item);
    setSalesItems(prev => [...prev, item]);
  };

  const handleUpdateItem = async (updated: SalesItem) => {
    await db.saveItem(updated);
    setSalesItems(prev => prev.map(i => i.id === updated.id ? updated : i));
  };

  const handleDeleteItem = async (id: string) => {
    await db.deleteItem(id);
    setSalesItems(prev => prev.filter(i => i.id !== id));
    setRecipes(prev => prev.filter(r => r.itemId !== id));
  };

  const handleSaveRecipe = async (recipe: Recipe) => {
    await db.saveRecipe(recipe);
    setRecipes(prev => {
      const exists = prev.some(r => r.itemId === recipe.itemId);
      if (exists) return prev.map(r => r.itemId === recipe.itemId ? recipe : r);
      return [...prev, recipe];
    });
  };

  const handleSaveSales = async (newSales: SaleEntry[]) => {
    await db.saveSales(newSales);
    setSales(prev => [...newSales, ...prev]);
  };

  const handleDeleteSale = async (id: string) => {
    await db.deleteSale(id);
    setSales(prev => prev.filter(s => s.id !== id));
  };

  const handleUpdateSale = async (id: string, quantity: number) => {
    await db.updateSale(id, quantity);
    setSales(prev => prev.map(s => s.id === id ? { ...s, quantitySold: quantity } : s));
  };

  if (isLoading) {
    return (
      <div className="min-h-screen bg-slate-900 flex flex-col items-center justify-center text-white space-y-4">
        <ChefHat className="w-16 h-16 text-emerald-500 animate-bounce" />
        <div className="flex items-center gap-2 text-xl font-bold">
          <Loader2 className="w-6 h-6 animate-spin text-emerald-500" />
          جاري الاتصال بقاعدة بيانات Turso...
        </div>
      </div>
    );
  }

  const renderContent = () => {
    switch (activeTab) {
      case 'materials':
        return (
          <MaterialsPage 
            materials={materials} 
            onAdd={handleAddMaterial} 
            onUpdate={handleUpdateMaterial} 
            onDelete={handleDeleteMaterial} 
          />
        );
      case 'items':
        return (
          <SalesItemsPage 
            items={salesItems} 
            onAdd={handleAddItem} 
            onUpdate={handleUpdateItem} 
            onDelete={handleDeleteItem} 
          />
        );
      case 'recipes':
        return (
          <RecipeBuilderPage 
            items={salesItems} 
            materials={materials} 
            recipes={recipes} 
            onSave={handleSaveRecipe} 
          />
        );
      case 'sales':
        return (
          <SalesEntryPage 
            items={salesItems} 
            sales={sales} 
            onSave={handleSaveSales} 
            onDeleteSale={handleDeleteSale}
            onUpdateSale={handleUpdateSale}
          />
        );
      case 'reports':
        return (
          <ReportsPage 
            materials={materials} 
            items={salesItems} 
            recipes={recipes} 
            sales={sales} 
          />
        );
      default:
        return null;
    }
  };

  return (
    <div className="flex min-h-screen bg-slate-50 text-slate-900" dir="rtl">
      <Sidebar 
        activeTab={activeTab} 
        setActiveTab={setActiveTab} 
        isOpen={isSidebarOpen} 
        setIsOpen={setIsSidebarOpen} 
      />
      <div className="flex-1 flex flex-col min-w-0">
        <Header 
          activeTab={activeTab} 
          onOpenSidebar={() => setIsSidebarOpen(true)} 
        />
        <main className="p-4 md:p-8 flex-1 overflow-y-auto">
          {renderContent()}
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Save, History, ShoppingCart, AlertCircle, Loader2, Trash2, Edit3, X, Check } from 'lucide-react';
import { SalesItem, SaleEntry } from '../types';

interface Props {
  items: SalesItem[];
  sales: SaleEntry[];
  onSave: (newSales: SaleEntry[]) => Promise<void>;
  onDeleteSale: (id: string) => Promise<void>;
  onUpdateSale: (id: string, quantity: number) => Promise<void>;
}

const SalesEntryPage: React.FC<Props> = ({ items, sales, onSave, onDeleteSale, onUpdateSale }) => {
  const [quantities, setQuantities] = useState<Record<string, number>>({});
  const [date, setDate] = useState<string>(new Date().toISOString().split('T')[0]);
  const [isSaving, setIsSaving] = useState(false);

  // States for editing history
  const [editingSaleId, setEditingSaleId] = useState<string | null>(null);
  const [editQuantity, setEditQuantity] = useState<number>(0);

  // Filter sales for the selected date
  const existingSalesForDate = sales.filter(s => s.date === date);

  const handleSave = async () => {
    const entries = Object.entries(quantities) as [string, number][];
    const validEntries = entries.filter(([_, qty]) => qty > 0);
    if (validEntries.length === 0) return alert('يرجى إدخال كمية مباعة لواحد على الأقل');

    setIsSaving(true);
    const newSales: SaleEntry[] = validEntries.map(([itemId, qty]) => ({
      id: Math.random().toString(36).substr(2, 9),
      itemId,
      quantitySold: qty,
      date
    }));

    await onSave(newSales);
    setQuantities({});
    setIsSaving(false);
    alert('تم حفظ المبيعات بنجاح!');
  };

  const handleDelete = async (id: string) => {
    if (window.confirm('هل أنت متأكد من حذف هذه العملية؟')) {
      await onDeleteSale(id);
    }
  };

  const startEdit = (sale: SaleEntry) => {
    setEditingSaleId(sale.id);
    setEditQuantity(sale.quantitySold);
  };

  const cancelEdit = () => {
    setEditingSaleId(null);
  };

  const saveEdit = async (id: string) => {
    if (editQuantity < 0) return alert('الكمية يجب أن تكون 0 أو أكثر');
    await onUpdateSale(id, editQuantity);
    setEditingSaleId(null);
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8">
      {/* Date and Input Form */}
      <section className="space-y-6">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div>
            <h3 className="text-lg font-bold text-slate-800 flex items-center gap-2">
              <ShoppingCart className="w-5 h-5 text-emerald-500" /> إدخال مبيعات جديدة
            </h3>
            <p className="text-sm text-slate-500">أدخل الكميات المباعة للتاريخ المختار</p>
          </div>
          <input 
            type="date" 
            className="border rounded-xl px-4 py-2 outline-none focus:ring-2 focus:ring-emerald-500 font-medium" 
            value={date} 
            onChange={(e) => {
              setDate(e.target.value);
              setQuantities({}); // Clear form on date change
            }} 
          />
        </div>

        <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
          <table className="w-full text-right">
            <thead className="bg-slate-50 border-b border-slate-200 text-slate-600">
              <tr>
                <th className="px-6 py-4 font-semibold">اسم الصنف</th>
                <th className="px-6 py-4 font-semibold w-48 text-center">الكمية المباعة الآن</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {items.map((item) => (
                <tr key={item.id} className="hover:bg-slate-50 transition-colors">
                  <td className="px-6 py-4 font-medium text-slate-700">{item.name}</td>
                  <td className="px-6 py-4">
                    <input 
                      type="number" 
                      min="0" 
                      placeholder="0" 
                      className="w-full text-center border rounded-xl px-4 py-2 font-mono font-bold outline-none focus:ring-2 focus:ring-emerald-500" 
                      value={quantities[item.id] || ''} 
                      onChange={(e) => setQuantities({...quantities, [item.id]: parseInt(e.target.value) || 0})} 
                    />
                  </td>
                </tr>
              ))}
              {items.length === 0 && (
                <tr><td colSpan={2} className="px-6 py-8 text-center text-slate-400">لا توجد أصناف مبيعات مدخلة</td></tr>
              )}
            </tbody>
          </table>
          <div className="p-6 bg-slate-50 border-t flex justify-end">
            <button 
              onClick={handleSave} 
              disabled={isSaving || (Object.values(quantities) as number[]).every(q => q <= 0)} 
              className="flex items-center gap-2 bg-emerald-500 text-white px-8 py-3 rounded-xl font-bold shadow-lg shadow-emerald-500/20 disabled:bg-slate-300 transition-all hover:scale-[1.02] active:scale-95"
            >
              {isSaving ? <Loader2 className="w-5 h-5 animate-spin" /> : <Save className="w-5 h-5" />} حفظ المبيعات
            </button>
          </div>
        </div>
      </section>

      {/* History Section for Selected Date */}
      <section className="space-y-4">
        <div className="flex items-center gap-2 px-2">
          <History className="w-5 h-5 text-slate-400" />
          <h3 className="text-lg font-bold text-slate-800">سجل مبيعات يوم: {date}</h3>
        </div>

        <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
          <table className="w-full text-right">
            <thead className="bg-slate-50 border-b border-slate-200 text-slate-500 text-sm">
              <tr>
                <th className="px-6 py-3 font-semibold">الصنف</th>
                <th className="px-6 py-3 font-semibold text-center">الكمية المسجلة</th>
                <th className="px-6 py-3 font-semibold w-32 text-center">إجراءات</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {existingSalesForDate.length > 0 ? (
                existingSalesForDate.map((sale) => {
                  const item = items.find(i => i.id === sale.itemId);
                  const isEditing = editingSaleId === sale.id;

                  return (
                    <tr key={sale.id} className="hover:bg-slate-50 transition-colors group">
                      <td className="px-6 py-4">
                        <span className="font-semibold text-slate-700">{item?.name || 'صنف محذوف'}</span>
                      </td>
                      <td className="px-6 py-4 text-center">
                        {isEditing ? (
                          <input 
                            type="number" 
                            className="w-24 text-center border-2 border-emerald-500 rounded-lg py-1 font-bold outline-none"
                            value={editQuantity}
                            onChange={(e) => setEditQuantity(parseInt(e.target.value) || 0)}
                            autoFocus
                          />
                        ) : (
                          <span className="font-mono font-bold text-slate-600">{sale.quantitySold}</span>
                        )}
                      </td>
                      <td className="px-6 py-4">
                        <div className="flex justify-center gap-2">
                          {isEditing ? (
                            <>
                              <button 
                                onClick={() => saveEdit(sale.id)}
                                className="p-2 text-emerald-600 hover:bg-emerald-50 rounded-lg transition-colors"
                                title="حفظ"
                              >
                                <Check className="w-4 h-4" />
                              </button>
                              <button 
                                onClick={cancelEdit}
                                className="p-2 text-slate-400 hover:bg-slate-100 rounded-lg transition-colors"
                                title="إلغاء"
                              >
                                <X className="w-4 h-4" />
                              </button>
                            </>
                          ) : (
                            <>
                              <button 
                                onClick={() => startEdit(sale)}
                                className="p-2 text-blue-500 hover:bg-blue-50 rounded-lg opacity-0 group-hover:opacity-100 transition-all"
                                title="تعديل"
                              >
                                <Edit3 className="w-4 h-4" />
                              </button>
                              <button 
                                onClick={() => handleDelete(sale.id)}
                                className="p-2 text-rose-500 hover:bg-rose-50 rounded-lg opacity-0 group-hover:opacity-100 transition-all"
                                title="حذف"
                              >
                                <Trash2 className="w-4 h-4" />
                              </button>
                            </>
                          )}
                        </div>
                      </td>
                    </tr>
                  );
                })
              ) : (
                <tr>
                  <td colSpan={3} className="px-6 py-10 text-center text-slate-400 italic">
                    لا توجد عمليات مسجلة لهذا التاريخ
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </section>
    </div>
  );
};

export default SalesEntryPage;

import React, { useState, useMemo } from 'react';
import { Layers, List, FileSpreadsheet, Printer, ChefHat, Calendar, Filter, RotateCcw } from 'lucide-react';
import { Material, SalesItem, Recipe, SaleEntry, AggregatedReportItem, DetailedReportItem } from '../types';

interface Props {
  materials: Material[];
  items: SalesItem[];
  recipes: Recipe[];
  sales: SaleEntry[];
}

const ReportsPage: React.FC<Props> = ({ materials, items, recipes, sales }) => {
  const [reportType, setReportType] = useState<'aggregated' | 'detailed'>('aggregated');

  // Date filter states
  const today = new Date().toISOString().split('T')[0];
  const firstDayOfMonth = new Date(new Date().getFullYear(), new Date().getMonth(), 1).toISOString().split('T')[0];

  const [startDate, setStartDate] = useState<string>(firstDayOfMonth);
  const [endDate, setEndDate] = useState<string>(today);

  // Filtered sales based on selected date range
  const filteredSales = useMemo(() => {
    return sales.filter(sale => {
      const saleDate = sale.date;
      return saleDate >= startDate && saleDate <= endDate;
    });
  }, [sales, startDate, endDate]);

  const aggregatedData = useMemo(() => {
    const reportMap: Record<string, { name: string; unit: string; total: number }> = {};
    materials.forEach(m => {
      reportMap[m.id] = { name: m.name, unit: m.unit, total: 0 };
    });

    filteredSales.forEach(sale => {
      const recipe = recipes.find(r => r.itemId === sale.itemId);
      if (recipe) {
        recipe.ingredients.forEach(ing => {
          if (reportMap[ing.materialId]) {
            reportMap[ing.materialId].total += ing.quantity * sale.quantitySold;
          }
        });
      }
    });
    return Object.values(reportMap).filter(item => item.total > 0);
  }, [materials, recipes, filteredSales]);

  const detailedData = useMemo(() => {
    const results: DetailedReportItem[] = [];
    const itemSalesMap: Record<string, number> = {};

    filteredSales.forEach(s => {
      itemSalesMap[s.itemId] = (itemSalesMap[s.itemId] || 0) + s.quantitySold;
    });

    Object.entries(itemSalesMap).forEach(([itemId, qtySold]) => {
      const item = items.find(i => i.id === itemId);
      const recipe = recipes.find(r => r.itemId === itemId);
      if (item && recipe) {
        results.push({
          itemName: item.name,
          quantitySold: qtySold,
          ingredients: recipe.ingredients.map(ing => {
            const mat = materials.find(m => m.id === ing.materialId);
            return {
              materialName: mat?.name || 'مجهول',
              unit: mat?.unit || '',
              consumedQuantity: ing.quantity * qtySold
            };
          })
        });
      }
    });
    return results;
  }, [items, recipes, filteredSales, materials]);

  const resetFilter = () => {
    setStartDate(firstDayOfMonth);
    setEndDate(today);
  };

  const exportCSV = () => {
    let csvContent = "";
    if (reportType === 'aggregated') {
      csvContent = "الخامة,وحدة القياس,إجمالي الاستهلاك\n";
      aggregatedData.forEach(row => {
        csvContent += `"${row.name}","${row.unit}",${row.total.toFixed(3)}\n`;
      });
    } else {
      csvContent = "الصنف,المباع,الخامة,الكمية المستهلكة,الوحدة\n";
      detailedData.forEach(item => {
        item.ingredients.forEach(ing => {
          csvContent += `"${item.itemName}",${item.quantitySold},"${ing.materialName}",${ing.consumedQuantity.toFixed(3)},"${ing.unit}"\n`;
        });
      });
    }

    const BOM = "\uFEFF";
    const blob = new Blob([BOM + csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    const url = URL.createObjectURL(blob);
    link.setAttribute("href", url);
    link.setAttribute("download", `تقرير_استهلاك_${reportType === 'aggregated' ? 'تجميعي' : 'تفصيلي'}_${startDate}_إلى_${endDate}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const exportPDF = () => {
    window.print();
  };

  return (
    <div className="max-w-5xl mx-auto space-y-6">
      {/* Print Branding Header */}
      <div className="hidden print:flex items-center justify-between mb-8 border-b-2 border-emerald-500 pb-4">
        <div className="flex items-center gap-3">
          <div className="bg-emerald-500 p-2 rounded-lg">
            <ChefHat className="w-8 h-8 text-white" />
          </div>
          <div>
            <h1 className="text-2xl font-bold text-slate-800 tracking-tight">CulinaTrack</h1>
            <p className="text-xs text-slate-500">نظام إدارة استهلاك المطاعم</p>
          </div>
        </div>
        <div className="text-left text-right">
          <h2 className="text-xl font-bold text-slate-700">تقرير استهلاك الخامات</h2>
          <p className="text-sm text-slate-500">الفترة من: {startDate} إلى: {endDate}</p>
        </div>
      </div>

      {/* Filter Section */}
      <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 no-print">
        <div className="flex items-center gap-2 mb-4 text-slate-700 font-bold">
          <Filter className="w-5 h-5 text-emerald-500" />
          <h3>تصفية التقرير حسب التاريخ</h3>
        </div>
        <div className="flex flex-col md:flex-row items-end gap-4">
          <div className="flex-1 w-full">
            <label className="block text-xs font-bold text-slate-500 mb-1 mr-1">من تاريخ</label>
            <div className="relative">
              <Calendar className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
              <input 
                type="date" 
                className="w-full border border-slate-200 rounded-xl pr-10 pl-4 py-2 outline-none focus:ring-2 focus:ring-emerald-500" 
                value={startDate} 
                onChange={(e) => setStartDate(e.target.value)} 
              />
            </div>
          </div>
          <div className="flex-1 w-full">
            <label className="block text-xs font-bold text-slate-500 mb-1 mr-1">إلى تاريخ</label>
            <div className="relative">
              <Calendar className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
              <input 
                type="date" 
                className="w-full border border-slate-200 rounded-xl pr-10 pl-4 py-2 outline-none focus:ring-2 focus:ring-emerald-500" 
                value={endDate} 
                onChange={(e) => setEndDate(e.target.value)} 
              />
            </div>
          </div>
          <button 
            onClick={resetFilter}
            className="flex items-center gap-2 px-4 py-2 text-slate-500 hover:text-emerald-600 hover:bg-emerald-50 rounded-xl transition-colors font-bold whitespace-nowrap"
          >
            <RotateCcw className="w-4 h-4" /> إعادة تعيين
          </button>
        </div>
      </div>

      <div className="flex flex-col md:flex-row items-center justify-between gap-4 no-print">
        <div className="flex bg-white p-1 rounded-2xl border border-slate-200 shadow-sm w-fit">
          <button
            onClick={() => setReportType('aggregated')}
            className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-sm font-bold transition-all ${
              reportType === 'aggregated' ? 'bg-emerald-500 text-white shadow-lg shadow-emerald-500/30' : 'text-slate-500'
            }`}
          >
            <Layers className="w-4 h-4" /> تقرير تجميعي
          </button>
          <button
            onClick={() => setReportType('detailed')}
            className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-sm font-bold transition-all ${
              reportType === 'detailed' ? 'bg-emerald-500 text-white shadow-lg shadow-emerald-500/30' : 'text-slate-500'
            }`}
          >
            <List className="w-4 h-4" /> تقرير تفصيلي
          </button>
        </div>

        <div className="flex gap-3">
          <button 
            onClick={exportCSV}
            className="flex items-center gap-2 text-sm text-emerald-700 border border-emerald-100 bg-emerald-50 px-4 py-2 rounded-xl hover:bg-emerald-100 transition-colors font-bold"
          >
            <FileSpreadsheet className="w-4 h-4" /> تصدير CSV
          </button>
          <button 
            onClick={exportPDF}
            className="flex items-center gap-2 text-sm text-slate-700 border border-slate-200 bg-white px-4 py-2 rounded-xl hover:bg-slate-50 transition-colors font-bold"
          >
            <Printer className="w-4 h-4" /> تصدير PDF / طباعة
          </button>
        </div>
      </div>

      {reportType === 'aggregated' ? (
        <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden print:border-none">
          <div className="p-6 border-b border-slate-100 bg-slate-50 print:bg-white flex justify-between items-center">
            <div>
              <h3 className="font-bold text-slate-800">إجمالي استهلاك الخامات</h3>
              <p className="text-xs text-slate-500">مجمع بناءً على الوصفات والمبيعات للفترة المحددة</p>
            </div>
            <div className="text-left text-xs font-mono text-slate-400">
              {startDate} ⮕ {endDate}
            </div>
          </div>
          <table className="w-full text-right">
            <thead className="bg-slate-50/50">
              <tr>
                <th className="px-6 py-4 font-semibold text-slate-600">الخامة</th>
                <th className="px-6 py-4 font-semibold text-slate-600">وحدة القياس</th>
                <th className="px-6 py-4 font-semibold text-slate-600 text-left">إجمالي الاستهلاك</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {aggregatedData.length > 0 ? aggregatedData.map((data, i) => (
                <tr key={i} className="hover:bg-slate-50 transition-colors">
                  <td className="px-6 py-4 font-bold text-slate-700">{data.name}</td>
                  <td className="px-6 py-4 text-slate-500">{data.unit}</td>
                  <td className="px-6 py-4 font-mono font-bold text-emerald-600 text-left">
                    {data.total.toLocaleString(undefined, { minimumFractionDigits: 3 })}
                  </td>
                </tr>
              )) : (
                <tr>
                  <td colSpan={3} className="px-6 py-12 text-center text-slate-400">لا توجد بيانات مبيعات في هذه الفترة لحساب الاستهلاك</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      ) : (
        <div className="space-y-6">
          {detailedData.length > 0 ? detailedData.map((item, idx) => (
            <div key={idx} className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden print:break-inside-avoid">
              <div className="p-4 bg-slate-900 text-white flex justify-between items-center print:bg-slate-100 print:text-slate-900 print:border-b">
                <span className="text-lg font-bold">{item.itemName}</span>
                <span className="bg-emerald-500 px-3 py-1 rounded-lg text-sm font-bold print:bg-slate-200">المباع: {item.quantitySold} وحدة</span>
              </div>
              <table className="w-full text-right">
                <thead className="bg-slate-50 border-b border-slate-100">
                  <tr>
                    <th className="px-6 py-3 text-xs font-bold text-slate-400 uppercase">الخامة</th>
                    <th className="px-6 py-3 text-xs font-bold text-slate-400 uppercase text-left">كمية الاستهلاك</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50">
                  {item.ingredients.map((ing, iIdx) => (
                    <tr key={iIdx}>
                      <td className="px-6 py-3 text-sm text-slate-600">{ing.materialName}</td>
                      <td className="px-6 py-3 text-sm font-mono font-bold text-slate-800 text-left">
                        {ing.consumedQuantity.toLocaleString(undefined, { minimumFractionDigits: 3 })} {ing.unit}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )) : (
            <div className="bg-white p-12 text-center text-slate-400 rounded-2xl border border-slate-200">
              لا توجد مبيعات تفصيلية لعرضها في الفترة المختارة.
            </div>
          )}
        </div>
      )}

      {/* Print Footer */}
      <div className="hidden print:block mt-8 text-center text-[10px] text-slate-400 border-t pt-4">
        هذا التقرير تم إنشاؤه آلياً بواسطة نظام CulinaTrack - الفترة المشمولة: {startDate} إلى {endDate}
      </div>
    </div>
  );
};

