export const initDb = async () => {
  await client.batch([
    "CREATE TABLE IF NOT EXISTS units (id TEXT PRIMARY KEY, name TEXT NOT NULL)",
    "CREATE TABLE IF NOT EXISTS materials (id TEXT PRIMARY KEY, name TEXT, unit TEXT)",
    "CREATE TABLE IF NOT EXISTS sales_items (id TEXT PRIMARY KEY, name TEXT)",
    "CREATE TABLE IF NOT EXISTS recipes (item_id TEXT, material_id TEXT, quantity REAL, PRIMARY KEY (item_id, material_id))",
    "CREATE TABLE IF NOT EXISTS sales (id TEXT PRIMARY KEY, item_id TEXT, quantity_sold INTEGER, sale_date TEXT)"
  ], "write");

  // Seed default units if empty
  const checkUnits = await client.execute("SELECT count(*) as count FROM units");
  if ((checkUnits.rows[0].count as number) === 0) {
    const defaultUnits = ['كجم', 'جرام', 'لتر', 'مل', 'حبة', 'كرتون', 'كيس'];
    const seedQueries = defaultUnits.map(u => ({
      sql: "INSERT INTO units (id, name) VALUES (?, ?)",
      args: [crypto.randomUUID(), u]
    }));
    await client.batch(seedQueries, "write");
  }
};

export const db = {
  // Units
  getUnits: async (): Promise<Unit[]> => {
    const rs = await client.execute("SELECT * FROM units ORDER BY name");
    return rs.rows as unknown as Unit[];
  },
  saveUnit: async (u: Unit) => {
    await client.execute({
      sql: "INSERT OR REPLACE INTO units (id, name) VALUES (?, ?)",
      args: [u.id, u.name]
    });
  },
  deleteUnit: async (id: string) => {
    await client.execute({ sql: "DELETE FROM units WHERE id = ?", args: [id] });
  },

  // Materials
  getMaterials: async (): Promise<Material[]> => {
    const rs = await client.execute("SELECT * FROM materials ORDER BY name");
    return rs.rows as unknown as Material[];
  },
  saveMaterial: async (m: Material) => {
    await client.execute({
      sql: "INSERT OR REPLACE INTO materials (id, name, unit) VALUES (?, ?, ?)",
      args: [m.id, m.name, m.unit]
    });
  },
  deleteMaterial: async (id: string) => {
    await client.execute({ sql: "DELETE FROM materials WHERE id = ?", args: [id] });
  },

  // Sales Items
  getItems: async (): Promise<SalesItem[]> => {
    const rs = await client.execute("SELECT * FROM sales_items ORDER BY name");
    return rs.rows as unknown as SalesItem[];
  },
  saveItem: async (i: SalesItem) => {
    await client.execute({
      sql: "INSERT OR REPLACE INTO sales_items (id, name) VALUES (?, ?)",
      args: [i.id, i.name]
    });
  },
  deleteItem: async (id: string) => {
    await client.batch([
      { sql: "DELETE FROM sales_items WHERE id = ?", args: [id] },
      { sql: "DELETE FROM recipes WHERE item_id = ?", args: [id] }
    ], "write");
  },

  // Recipes
  getRecipes: async (): Promise<Recipe[]> => {
    const rs = await client.execute("SELECT * FROM recipes");
    const grouped: Record<string, Recipe> = {};
    rs.rows.forEach(row => {
      const itemId = row.item_id as string;
      if (!grouped[itemId]) grouped[itemId] = { itemId, ingredients: [] };
      grouped[itemId].ingredients.push({
        materialId: row.material_id as string,
        quantity: row.quantity as number
      });
    });
    return Object.values(grouped);
  },
  saveRecipe: async (recipe: Recipe) => {
    const queries = [
      { sql: "DELETE FROM recipes WHERE item_id = ?", args: [recipe.itemId] },
      ...recipe.ingredients.map(ing => ({
        sql: "INSERT INTO recipes (item_id, material_id, quantity) VALUES (?, ?, ?)",
        args: [recipe.itemId, ing.materialId, ing.quantity]
      }))
    ];
    await client.batch(queries, "write");
  },

  // Sales
  getSales: async (): Promise<SaleEntry[]> => {
    const rs = await client.execute("SELECT id, item_id as itemId, quantity_sold as quantitySold, sale_date as date FROM sales ORDER BY sale_date DESC");
    return rs.rows as unknown as SaleEntry[];
  },
  saveSales: async (newSales: SaleEntry[]) => {
    const queries = newSales.map(s => ({
      sql: "INSERT INTO sales (id, item_id, quantity_sold, sale_date) VALUES (?, ?, ?, ?)",
      args: [s.id, s.itemId, s.quantitySold, s.date]
    }));
    await client.batch(queries, "write");
  },
  deleteSale: async (id: string) => {
    await client.execute({ sql: "DELETE FROM sales WHERE id = ?", args: [id] });
  },
  updateSale: async (id: string, quantity: number) => {
    await client.execute({
      sql: "UPDATE sales SET quantity_sold = ? WHERE id = ?",
      args: [quantity, id]
    });
  }
};

import React, { useState, useEffect } from 'react';
import { ChefHat, Loader2 } from 'lucide-react';
import { 
  Material, 
  SalesItem, 
  Recipe, 
  SaleEntry,
  Unit
} from './types';
import { db, initDb } from './db';

// Components
import Sidebar from './components/Sidebar';
import Header from './components/Header';
import MaterialsPage from './components/MaterialsPage';
import SalesItemsPage from './components/SalesItemsPage';
import RecipeBuilderPage from './components/RecipeBuilderPage';
import SalesEntryPage from './components/SalesEntryPage';
import ReportsPage from './components/ReportsPage';
import UnitsPage from './components/UnitsPage';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'materials' | 'items' | 'recipes' | 'sales' | 'reports' | 'units'>('items');
  const [isLoading, setIsLoading] = useState(true);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  const [materials, setMaterials] = useState<Material[]>([]);
  const [units, setUnits] = useState<Unit[]>([]);
  const [salesItems, setSalesItems] = useState<SalesItem[]>([]);
  const [recipes, setRecipes] = useState<Recipe[]>([]);
  const [sales, setSales] = useState<SaleEntry[]>([]);

  // Initial Load
  useEffect(() => {
    const loadData = async () => {
      try {
        await initDb();
        const [mats, itemUnits, items, recs, sls] = await Promise.all([
          db.getMaterials(),
          db.getUnits(),
          db.getItems(),
          db.getRecipes(),
          db.getSales()
        ]);
        setMaterials(mats);
        setUnits(itemUnits);
        setSalesItems(items);
        setRecipes(recs);
        setSales(sls);
      } catch (error) {
        console.error("Error loading data from Turso:", error);
        alert("حدث خطأ أثناء الاتصال بقاعدة البيانات.");
      } finally {
        setIsLoading(false);
      }
    };
    loadData();
  }, []);

  const handleAddUnit = async (u: Unit) => {
    await db.saveUnit(u);
    setUnits(prev => [...prev, u].sort((a,b) => a.name.localeCompare(b.name)));
  };

  const handleUpdateUnit = async (updated: Unit) => {
    await db.saveUnit(updated);
    setUnits(prev => prev.map(u => u.id === updated.id ? updated : u).sort((a,b) => a.name.localeCompare(b.name)));
  };

  const handleDeleteUnit = async (id: string) => {
    await db.deleteUnit(id);
    setUnits(prev => prev.filter(u => u.id !== id));
  };

  const handleAddMaterial = async (m: Material) => {
    await db.saveMaterial(m);
    setMaterials(prev => [...prev, m]);
  };

  const handleUpdateMaterial = async (updated: Material) => {
    await db.saveMaterial(updated);
    setMaterials(prev => prev.map(m => m.id === updated.id ? updated : m));
  };

  const handleDeleteMaterial = async (id: string) => {
    await db.deleteMaterial(id);
    setMaterials(prev => prev.filter(m => m.id !== id));
  };

  const handleAddItem = async (item: SalesItem) => {
    await db.saveItem(item);
    setSalesItems(prev => [...prev, item]);
  };

  const handleUpdateItem = async (updated: SalesItem) => {
    await db.saveItem(updated);
    setSalesItems(prev => prev.map(i => i.id === updated.id ? updated : i));
  };

  const handleDeleteItem = async (id: string) => {
    await db.deleteItem(id);
    setSalesItems(prev => prev.filter(i => i.id !== id));
    setRecipes(prev => prev.filter(r => r.itemId !== id));
  };

  const handleSaveRecipe = async (recipe: Recipe) => {
    await db.saveRecipe(recipe);
    setRecipes(prev => {
      const exists = prev.some(r => r.itemId === recipe.itemId);
      if (exists) return prev.map(r => r.itemId === recipe.itemId ? recipe : r);
      return [...prev, recipe];
    });
  };

  const handleSaveSales = async (newSales: SaleEntry[]) => {
    await db.saveSales(newSales);
    setSales(prev => [...newSales, ...prev]);
  };

  const handleDeleteSale = async (id: string) => {
    await db.deleteSale(id);
    setSales(prev => prev.filter(s => s.id !== id));
  };

  const handleUpdateSale = async (id: string, quantity: number) => {
    await db.updateSale(id, quantity);
    setSales(prev => prev.map(s => s.id === id ? { ...s, quantitySold: quantity } : s));
  };

  if (isLoading) {
    return (
      <div className="min-h-screen bg-slate-900 flex flex-col items-center justify-center text-white space-y-4">
        <ChefHat className="w-16 h-16 text-emerald-500 animate-bounce" />
        <div className="flex items-center gap-2 text-xl font-bold">
          <Loader2 className="w-6 h-6 animate-spin text-emerald-500" />
          جاري الاتصال بقاعدة بيانات Turso...
        </div>
      </div>
    );
  }

  const renderContent = () => {
    switch (activeTab) {
      case 'units':
        return (
          <UnitsPage 
            units={units} 
            onAdd={handleAddUnit} 
            onUpdate={handleUpdateUnit} 
            onDelete={handleDeleteUnit} 
          />
        );
      case 'materials':
        return (
          <MaterialsPage 
            materials={materials}
            units={units} 
            onAdd={handleAddMaterial} 
            onUpdate={handleUpdateMaterial} 
            onDelete={handleDeleteMaterial} 
          />
        );
      case 'items':
        return (
          <SalesItemsPage 
            items={salesItems} 
            onAdd={handleAddItem} 
            onUpdate={handleUpdateItem} 
            onDelete={handleDeleteItem} 
          />
        );
      case 'recipes':
        return (
          <RecipeBuilderPage 
            items={salesItems} 
            materials={materials} 
            recipes={recipes} 
            onSave={handleSaveRecipe} 
          />
        );
      case 'sales':
        return (
          <SalesEntryPage 
            items={salesItems} 
            sales={sales} 
            onSave={handleSaveSales} 
            onDeleteSale={handleDeleteSale}
            onUpdateSale={handleUpdateSale}
          />
        );
      case 'reports':
        return (
          <ReportsPage 
            materials={materials} 
            items={salesItems} 
            recipes={recipes} 
            sales={sales} 
          />
        );
      default:
        return null;
    }
  };

  return (
    <div className="flex min-h-screen bg-slate-50 text-slate-900" dir="rtl">
      <Sidebar 
        activeTab={activeTab} 
        setActiveTab={setActiveTab} 
        isOpen={isSidebarOpen} 
        setIsOpen={setIsSidebarOpen} 
      />
      <div className="flex-1 flex flex-col min-w-0">
        <Header 
          activeTab={activeTab} 
          onOpenSidebar={() => setIsSidebarOpen(true)} 
        />
        <main className="p-4 md:p-8 flex-1 overflow-y-auto">
          {renderContent()}
        </main>
      </div>
    </div>
  );
};

export default App;

