import React, { useState } from 'react';
import { Plus, Trash2, Package, AlertCircle, Edit3, Save, X } from 'lucide-react';
import { Material, Unit } from '../types';

interface Props {
  materials: Material[];
  units: Unit[];
  onAdd: (m: Material) => Promise<void>;
  onUpdate: (m: Material) => Promise<void>;
  onDelete: (id: string) => Promise<void>;
}

const MaterialsPage: React.FC<Props> = ({ materials, units, onAdd, onUpdate, onDelete }) => {
  const [name, setName] = useState('');
  const [unit, setUnit] = useState(units[0]?.name || 'كجم');
  const [error, setError] = useState('');

  const [editingId, setEditingId] = useState<string | null>(null);
  const [editName, setEditName] = useState('');
  const [editUnit, setEditUnit] = useState('');
  const [editError, setEditError] = useState('');

  // Set default unit when units load
  React.useEffect(() => {
    if (!unit && units.length > 0) setUnit(units[0].name);
  }, [units]);

  const addMaterial = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    if (!name.trim()) return setError('يرجى إدخل اسم الخامة');
    if (materials.some(m => m.name.trim().toLowerCase() === name.trim().toLowerCase())) 
      return setError('هذه الخامة موجودة بالفعل');

    const newMaterial: Material = { id: crypto.randomUUID(), name: name.trim(), unit };
    await onAdd(newMaterial);
    setName('');
  };

  const saveEdit = async (id: string) => {
    if (!editName.trim()) return setEditError('الاسم مطلوب');
    if (materials.some(m => m.id !== id && m.name.trim().toLowerCase() === editName.trim().toLowerCase()))
      return setEditError('هذا الاسم مستخدم لخامة أخرى');

    await onUpdate({ id, name: editName.trim(), unit: editUnit });
    setEditingId(null);
  };

  const handleDelete = async (id: string, name: string) => {
    if (window.confirm(`هل أنت متأكد من حذف الخامة "${name}"؟ قد يؤثر ذلك على الوصفات التي تستخدمها.`)) {
      await onDelete(id);
    }
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6">
      <div className="bg-white dark:bg-slate-900 p-6 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-800 transition-colors">
        <h3 className="text-lg font-semibold mb-4 flex items-center gap-2 dark:text-white">
          <Plus className="w-5 h-5 text-emerald-500" /> إضافة خامة جديدة
        </h3>
        <form onSubmit={addMaterial} className="space-y-4">
          <div className="flex flex-col md:flex-row gap-4">
            <div className="flex-1">
              <input
                type="text" placeholder="اسم الخامة (مثال: لحم بقري)"
                className={`w-full border ${error ? 'border-rose-500' : 'border-slate-200 dark:border-slate-700'} bg-white dark:bg-slate-800 dark:text-white rounded-xl px-4 py-2 outline-none focus:ring-2 focus:ring-emerald-500 transition-all`}
                value={name} onChange={(e) => { setName(e.target.value); if (error) setError(''); }}
              />
              {error && <p className="text-rose-500 text-xs mt-1 flex items-center gap-1"><AlertCircle className="w-3 h-3" /> {error}</p>}
            </div>
            <select
              className="border border-slate-200 dark:border-slate-700 rounded-xl px-4 py-2 bg-white dark:bg-slate-800 dark:text-white outline-none"
              value={unit} onChange={(e) => setUnit(e.target.value)}
            >
              {units.map(u => <option key={u.id} value={u.name}>{u.name}</option>)}
              {units.length === 0 && <option value="كجم">كجم</option>}
            </select>
            <button className="bg-emerald-500 text-white px-6 py-2 rounded-xl hover:bg-emerald-600 font-bold transition-transform active:scale-95">إضافة</button>
          </div>
        </form>
      </div>

      <div className="bg-white dark:bg-slate-900 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-800 overflow-hidden transition-colors">
        <div className="overflow-x-auto">
          <table className="w-full text-right">
            <thead className="bg-slate-50 dark:bg-slate-800/50 border-b border-slate-200 dark:border-slate-800 text-slate-600 dark:text-slate-400">
              <tr><th className="px-6 py-4 font-semibold">اسم الخامة</th><th className="px-6 py-4 font-semibold">وحدة القياس</th><th className="px-6 py-4 font-semibold w-32">إجراءات</th></tr>
            </thead>
            <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
              {materials.map((m) => (
                <tr key={m.id} className="hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors">
                  {editingId === m.id ? (
                    <>
                      <td className="px-6 py-3">
                        <input type="text" className="w-full border dark:border-slate-700 bg-white dark:bg-slate-800 dark:text-white rounded-lg px-3 py-1 outline-none focus:ring-2 focus:ring-emerald-500" value={editName} onChange={(e) => setEditName(e.target.value)} autoFocus />
                      </td>
                      <td className="px-6 py-3">
                        <select className="w-full border dark:border-slate-700 bg-white dark:bg-slate-800 dark:text-white rounded-lg px-2 py-1 outline-none" value={editUnit} onChange={(e) => setEditUnit(e.target.value)}>
                          {units.map(u => <option key={u.id} value={u.name}>{u.name}</option>)}
                        </select>
                      </td>
                      <td className="px-6 py-3 flex gap-2">
                        <button onClick={() => saveEdit(m.id)} className="p-1.5 text-emerald-600 hover:bg-emerald-50 dark:hover:bg-emerald-900/20 rounded-lg"><Save className="w-4 h-4" /></button>
                        <button onClick={() => setEditingId(null)} className="p-1.5 text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-lg"><X className="w-4 h-4" /></button>
                      </td>
                    </>
                  ) : (
                    <>
                      <td className="px-6 py-4 flex items-center gap-3 dark:text-slate-200"><Package className="w-4 h-4 text-slate-400" />{m.name}</td>
                      <td className="px-6 py-4 dark:text-slate-300">{m.unit}</td>
                      <td className="px-6 py-4 flex gap-1">
                        <button onClick={() => { setEditingId(m.id); setEditName(m.name); setEditUnit(m.unit); }} className="p-2 text-blue-500 dark:text-blue-400 hover:bg-blue-50 dark:hover:bg-blue-900/20 rounded-lg" title="تعديل"><Edit3 className="w-4 h-4" /></button>
                        <button onClick={() => handleDelete(m.id, m.name)} className="p-2 text-rose-500 dark:text-rose-400 hover:bg-rose-50 dark:hover:bg-rose-900/20 rounded-lg" title="حذف"><Trash2 className="w-4 h-4" /></button>
                      </td>
                    </>
                  )}
                </tr>
              ))}
              {materials.length === 0 && (
                <tr>
                  <td colSpan={3} className="px-6 py-8 text-center text-slate-400 dark:text-slate-600 italic">لا توجد خامات مضافة</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default MaterialsPage;

import React, { useState } from 'react';
import { Save, History, ShoppingCart, Loader2, Trash2, Edit3, X, Check, Plus, AlertCircle } from 'lucide-react';
import { SalesItem, SaleEntry } from '../types';

interface Props {
  items: SalesItem[];
  sales: SaleEntry[];
  onSave: (newSales: SaleEntry[]) => Promise<void>;
  onDeleteSale: (id: string) => Promise<void>;
  onUpdateSale: (id: string, quantity: number) => Promise<void>;
}

interface NewSaleRow {
  tempId: string;
  itemId: string;
  quantity: number;
}

const SalesEntryPage: React.FC<Props> = ({ items, sales, onSave, onDeleteSale, onUpdateSale }) => {
  const [rows, setRows] = useState<NewSaleRow[]>([{ tempId: crypto.randomUUID(), itemId: '', quantity: 0 }]);
  const [date, setDate] = useState<string>(new Date().toISOString().split('T')[0]);
  const [isSaving, setIsSaving] = useState(false);

  const [editingSaleId, setEditingSaleId] = useState<string | null>(null);
  const [editQuantity, setEditQuantity] = useState<number>(0);

  const existingSalesForDate = sales.filter(s => s.date === date);

  const addRow = () => {
    setRows([...rows, { tempId: crypto.randomUUID(), itemId: '', quantity: 0 }]);
  };

  const removeRow = (tempId: string) => {
    if (rows.length === 1) {
      setRows([{ tempId: crypto.randomUUID(), itemId: '', quantity: 0 }]);
    } else {
      setRows(rows.filter(r => r.tempId !== tempId));
    }
  };

  const updateRow = (tempId: string, field: keyof NewSaleRow, value: any) => {
    setRows(rows.map(r => r.tempId === tempId ? { ...r, [field]: value } : r));
  };

  const handleSave = async () => {
    const validRows = rows.filter(r => r.itemId && r.quantity > 0);
    if (validRows.length === 0) return alert('يرجى اختيار صنف وإدخال كمية لواحد على الأقل');

    setIsSaving(true);
    try {
      const newEntries: SaleEntry[] = validRows.map(r => ({
        id: crypto.randomUUID(),
        itemId: r.itemId,
        quantitySold: r.quantity,
        date
      }));

      await onSave(newEntries);
      setRows([{ tempId: crypto.randomUUID(), itemId: '', quantity: 0 }]);
    } catch (error) {
      console.error(error);
    } finally {
      setIsSaving(false);
    }
  };

  const startEdit = (sale: SaleEntry) => {
    setEditingSaleId(sale.id);
    setEditQuantity(sale.quantitySold);
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8">
      {/* New Sales Form with Dynamic Rows */}
      <section className="space-y-6">
        <div className="bg-white dark:bg-slate-900 p-6 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-800 flex flex-col md:flex-row md:items-center justify-between gap-4 transition-colors">
          <div>
            <h3 className="text-lg font-bold text-slate-800 dark:text-white flex items-center gap-2">
              <ShoppingCart className="w-5 h-5 text-emerald-500" /> تسجيل مبيعات جديدة
            </h3>
            <p className="text-sm text-slate-500 dark:text-slate-400">اختر الأصناف وأدخل الكميات لتاريخ اليوم</p>
          </div>
          <input 
            type="date" 
            className="border border-slate-200 dark:border-slate-700 rounded-xl px-4 py-2 outline-none focus:ring-2 focus:ring-emerald-500 font-medium bg-slate-50 dark:bg-slate-800 dark:text-white" 
            value={date} 
            onChange={(e) => setDate(e.target.value)} 
          />
        </div>

        <div className="bg-white dark:bg-slate-900 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-800 overflow-hidden transition-colors">
          <div className="p-4 bg-slate-50 dark:bg-slate-800/50 border-b border-slate-100 dark:border-slate-800 flex justify-between items-center">
            <span className="text-sm font-bold text-slate-500 dark:text-slate-400">تفاصيل المبيعات</span>
            <button 
              onClick={addRow}
              className="flex items-center gap-1 text-xs bg-slate-800 dark:bg-slate-700 text-white px-3 py-1.5 rounded-lg font-bold hover:bg-slate-700 dark:hover:bg-slate-600 transition-colors"
            >
              <Plus className="w-3.5 h-3.5" /> إضافة صف
            </button>
          </div>

          <div className="p-6 space-y-3">
            {rows.map((row) => (
              <div key={row.tempId} className="flex flex-col sm:flex-row gap-3 items-end sm:items-center animate-in fade-in slide-in-from-right-2 duration-200">
                <div className="flex-1 w-full">
                  <label className="block text-[10px] font-bold text-slate-400 dark:text-slate-500 mb-1 mr-1">الصنف المباع</label>
                  <select 
                    className="w-full border border-slate-200 dark:border-slate-700 rounded-xl px-4 py-2.5 outline-none focus:ring-2 focus:ring-emerald-500 bg-white dark:bg-slate-800 dark:text-white"
                    value={row.itemId}
                    onChange={(e) => updateRow(row.tempId, 'itemId', e.target.value)}
                  >
                    <option value="">-- اختر صنفاً --</option>
                    {items.map(i => (
                      <option key={i.id} value={i.id}>{i.name}</option>
                    ))}
                  </select>
                </div>
                <div className="w-full sm:w-32">
                  <label className="block text-[10px] font-bold text-slate-400 dark:text-slate-500 mb-1 mr-1">الكمية</label>
                  <input 
                    type="number" 
                    min="1"
                    placeholder="0"
                    className="w-full border border-slate-200 dark:border-slate-700 rounded-xl px-4 py-2.5 text-center font-mono font-bold outline-none focus:ring-2 focus:ring-emerald-500 bg-white dark:bg-slate-800 dark:text-white"
                    value={row.quantity || ''}
                    onChange={(e) => updateRow(row.tempId, 'quantity', parseInt(e.target.value) || 0)}
                  />
                </div>
                <button 
                  onClick={() => removeRow(row.tempId)}
                  className="p-2.5 text-rose-500 hover:bg-rose-50 dark:hover:bg-rose-900/20 rounded-xl transition-colors"
                  title="حذف الصف"
                >
                  <Trash2 className="w-5 h-5" />
                </button>
              </div>
            ))}
          </div>

          <div className="p-6 bg-slate-50 dark:bg-slate-800/30 border-t border-slate-100 dark:border-slate-800 flex justify-end">
            <button 
              onClick={handleSave} 
              disabled={isSaving || rows.every(r => !r.itemId || r.quantity <= 0)} 
              className="flex items-center gap-2 bg-emerald-500 text-white px-8 py-3 rounded-xl font-bold shadow-lg shadow-emerald-500/20 disabled:bg-slate-300 dark:disabled:bg-slate-700 transition-all hover:scale-[1.02] active:scale-95"
            >
              {isSaving ? <Loader2 className="w-5 h-5 animate-spin" /> : <Save className="w-5 h-5" />} حفظ وإرسال
            </button>
          </div>
        </div>
      </section>

      {/* History Section for Selected Date */}
      <section className="space-y-4">
        <div className="flex items-center justify-between px-2">
          <div className="flex items-center gap-2">
            <History className="w-5 h-5 text-slate-400" />
            <h3 className="text-lg font-bold text-slate-800 dark:text-slate-200">تاريخ مبيعات يوم: {date}</h3>
          </div>
          <span className="text-xs bg-slate-100 dark:bg-slate-800 px-3 py-1 rounded-full font-bold text-slate-500 dark:text-slate-400">
            عدد السجلات: {existingSalesForDate.length}
          </span>
        </div>

        <div className="bg-white dark:bg-slate-900 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-800 overflow-hidden transition-colors">
          <div className="overflow-x-auto">
            <table className="w-full text-right">
              <thead className="bg-slate-50 dark:bg-slate-800/50 border-b border-slate-200 dark:border-slate-800 text-slate-500 dark:text-slate-400 text-xs uppercase tracking-wider">
                <tr>
                  <th className="px-6 py-4 font-bold">اسم الصنف</th>
                  <th className="px-6 py-4 font-bold text-center">الكمية المسجلة</th>
                  <th className="px-6 py-4 font-bold w-32 text-center">إجراءات</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                {existingSalesForDate.length > 0 ? (
                  existingSalesForDate.map((sale) => {
                    const item = items.find(i => i.id === sale.itemId);
                    const isEditing = editingSaleId === sale.id;

                    return (
                      <tr key={sale.id} className="hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors group">
                        <td className="px-6 py-4">
                          <span className="font-bold text-slate-700 dark:text-slate-200">{item?.name || 'صنف غير معروف'}</span>
                        </td>
                        <td className="px-6 py-4 text-center">
                          {isEditing ? (
                            <input 
                              type="number" 
                              className="w-24 text-center border-2 border-emerald-500 rounded-lg py-1 font-bold outline-none bg-white dark:bg-slate-800 dark:text-white"
                              value={editQuantity}
                              onChange={(e) => setEditQuantity(parseInt(e.target.value) || 0)}
                              autoFocus
                            />
                          ) : (
                            <span className="font-mono font-bold text-slate-600 dark:text-slate-300 bg-slate-100 dark:bg-slate-800 px-3 py-1 rounded-lg">{sale.quantitySold}</span>
                          )}
                        </td>
                        <td className="px-6 py-4">
                          <div className="flex justify-center gap-2">
                            {isEditing ? (
                              <>
                                <button 
                                  onClick={() => { onUpdateSale(sale.id, editQuantity); setEditingSaleId(null); }}
                                  className="p-2 text-emerald-600 dark:text-emerald-400 hover:bg-emerald-50 dark:hover:bg-emerald-900/20 rounded-lg"
                                >
                                  <Check className="w-4 h-4" />
                                </button>
                                <button 
                                  onClick={() => setEditingSaleId(null)}
                                  className="p-2 text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-lg"
                                >
                                  <X className="w-4 h-4" />
                                </button>
                              </>
                            ) : (
                              <>
                                <button 
                                  onClick={() => startEdit(sale)}
                                  className="p-2 text-blue-500 dark:text-blue-400 hover:bg-blue-50 dark:hover:bg-blue-900/20 rounded-lg"
                                >
                                  <Edit3 className="w-4 h-4" />
                                </button>
                                <button 
                                  onClick={() => { if(confirm('حذف هذه العملية؟')) onDeleteSale(sale.id); }}
                                  className="p-2 text-rose-500 dark:text-rose-400 hover:bg-rose-50 dark:hover:bg-rose-900/20 rounded-lg"
                                >
                                  <Trash2 className="w-4 h-4" />
                                </button>
                              </>
                            )}
                          </div>
                        </td>
                      </tr>
                    );
                  })
                ) : (
                  <tr>
                    <td colSpan={3} className="px-6 py-12 text-center text-slate-400 dark:text-slate-600 italic">
                      <div className="flex flex-col items-center gap-2">
                        <AlertCircle className="w-8 h-8 opacity-20" />
                        <span>لا توجد مبيعات مسجلة لهذا اليوم حتى الآن</span>
                      </div>
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      </section>
    </div>
  );
};

export default SalesEntryPage;

import React, { useState, useMemo } from 'react';
import { Layers, List, FileSpreadsheet, Printer, ChefHat, Calendar, Filter, RotateCcw } from 'lucide-react';
import { Material, SalesItem, Recipe, SaleEntry, AggregatedReportItem, DetailedReportItem } from '../types';

interface Props {
  materials: Material[];
  items: SalesItem[];
  recipes: Recipe[];
  sales: SaleEntry[];
}

const ReportsPage: React.FC<Props> = ({ materials, items, recipes, sales }) => {
  const [reportType, setReportType] = useState<'aggregated' | 'detailed'>('aggregated');

  // Date filter states
  const today = new Date().toISOString().split('T')[0];
  const firstDayOfMonth = new Date(new Date().getFullYear(), new Date().getMonth(), 1).toISOString().split('T')[0];

  const [startDate, setStartDate] = useState<string>(firstDayOfMonth);
  const [endDate, setEndDate] = useState<string>(today);

  // Filtered sales based on selected date range
  const filteredSales = useMemo(() => {
    return sales.filter(sale => {
      const saleDate = sale.date;
      return saleDate >= startDate && saleDate <= endDate;
    });
  }, [sales, startDate, endDate]);

  const aggregatedData = useMemo(() => {
    const reportMap: Record<string, { name: string; unit: string; total: number }> = {};
    materials.forEach(m => {
      reportMap[m.id] = { name: m.name, unit: m.unit, total: 0 };
    });

    filteredSales.forEach(sale => {
      const recipe = recipes.find(r => r.itemId === sale.itemId);
      if (recipe) {
        recipe.ingredients.forEach(ing => {
          if (reportMap[ing.materialId]) {
            reportMap[ing.materialId].total += ing.quantity * sale.quantitySold;
          }
        });
      }
    });
    return Object.values(reportMap).filter(item => item.total > 0);
  }, [materials, recipes, filteredSales]);

  const detailedData = useMemo(() => {
    const results: DetailedReportItem[] = [];
    const itemSalesMap: Record<string, number> = {};

    filteredSales.forEach(s => {
      itemSalesMap[s.itemId] = (itemSalesMap[s.itemId] || 0) + s.quantitySold;
    });

    Object.entries(itemSalesMap).forEach(([itemId, qtySold]) => {
      const item = items.find(i => i.id === itemId);
      const recipe = recipes.find(r => r.itemId === itemId);
      if (item && recipe) {
        results.push({
          itemName: item.name,
          quantitySold: qtySold,
          ingredients: recipe.ingredients.map(ing => {
            const mat = materials.find(m => m.id === ing.materialId);
            return {
              materialName: mat?.name || 'مجهول',
              unit: mat?.unit || '',
              consumedQuantity: ing.quantity * qtySold
            };
          })
        });
      }
    });
    return results;
  }, [items, recipes, filteredSales, materials]);

  const resetFilter = () => {
    setStartDate(firstDayOfMonth);
    setEndDate(today);
  };

  const exportCSV = () => {
    let csvContent = "";
    if (reportType === 'aggregated') {
      csvContent = "الخامة,وحدة القياس,إجمالي الاستهلاك\n";
      aggregatedData.forEach(row => {
        csvContent += `"${row.name}","${row.unit}",${row.total.toFixed(3)}\n`;
      });
    } else {
      csvContent = "الصنف,المباع,الخامة,الكمية المستهلكة,الوحدة\n";
      detailedData.forEach(item => {
        item.ingredients.forEach(ing => {
          csvContent += `"${item.itemName}",${item.quantitySold},"${ing.materialName}",${ing.consumedQuantity.toFixed(3)},"${ing.unit}"\n`;
        });
      });
    }

    const BOM = "\uFEFF";
    const blob = new Blob([BOM + csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    const url = URL.createObjectURL(blob);
    link.setAttribute("href", url);
    link.setAttribute("download", `تقرير_استهلاك_${reportType === 'aggregated' ? 'تجميعي' : 'تفصيلي'}_${startDate}_إلى_${endDate}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const exportPDF = () => {
    window.print();
  };

  return (
    <div className="max-w-5xl mx-auto space-y-6">
      {/* Print Branding Header */}
      <div className="hidden print:flex items-center justify-between mb-8 border-b-2 border-emerald-500 pb-4">
        <div className="flex items-center gap-3">
          <div className="bg-emerald-500 p-2 rounded-lg">
            <ChefHat className="w-8 h-8 text-white" />
          </div>
          <div>
            <h1 className="text-2xl font-bold text-slate-800 tracking-tight">CulinaTrack</h1>
            <p className="text-xs text-slate-500">نظام إدارة استهلاك المطاعم</p>
          </div>
        </div>
        <div className="text-left text-right">
          <h2 className="text-xl font-bold text-slate-700">تقرير استهلاك الخامات</h2>
          <p className="text-sm text-slate-500">الفترة من: {startDate} إلى: {endDate}</p>
        </div>
      </div>

      {/* Filter Section */}
      <div className="bg-white dark:bg-slate-900 p-6 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-800 no-print transition-colors">
        <div className="flex items-center gap-2 mb-4 text-slate-700 dark:text-slate-200 font-bold">
          <Filter className="w-5 h-5 text-emerald-500" />
          <h3>تصفية التقرير حسب التاريخ</h3>
        </div>
        <div className="flex flex-col md:flex-row items-end gap-4">
          <div className="flex-1 w-full">
            <label className="block text-xs font-bold text-slate-500 dark:text-slate-400 mb-1 mr-1">من تاريخ</label>
            <div className="relative">
              <Calendar className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
              <input 
                type="date" 
                className="w-full border border-slate-200 dark:border-slate-700 rounded-xl pr-10 pl-4 py-2 outline-none focus:ring-2 focus:ring-emerald-500 bg-white dark:bg-slate-800 dark:text-white" 
                value={startDate} 
                onChange={(e) => setStartDate(e.target.value)} 
              />
            </div>
          </div>
          <div className="flex-1 w-full">
            <label className="block text-xs font-bold text-slate-500 dark:text-slate-400 mb-1 mr-1">إلى تاريخ</label>
            <div className="relative">
              <Calendar className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
              <input 
                type="date" 
                className="w-full border border-slate-200 dark:border-slate-700 rounded-xl pr-10 pl-4 py-2 outline-none focus:ring-2 focus:ring-emerald-500 bg-white dark:bg-slate-800 dark:text-white" 
                value={endDate} 
                onChange={(e) => setEndDate(e.target.value)} 
              />
            </div>
          </div>
          <button 
            onClick={resetFilter}
            className="flex items-center gap-2 px-4 py-2 text-slate-500 dark:text-slate-400 hover:text-emerald-600 dark:hover:text-emerald-400 hover:bg-emerald-50 dark:hover:bg-emerald-900/20 rounded-xl transition-colors font-bold whitespace-nowrap"
          >
            <RotateCcw className="w-4 h-4" /> إعادة تعيين
          </button>
        </div>
      </div>

      <div className="flex flex-col md:flex-row items-center justify-between gap-4 no-print">
        <div className="flex bg-white dark:bg-slate-900 p-1 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm w-fit transition-colors">
          <button
            onClick={() => setReportType('aggregated')}
            className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-sm font-bold transition-all ${
              reportType === 'aggregated' ? 'bg-emerald-500 text-white shadow-lg shadow-emerald-500/30' : 'text-slate-500 dark:text-slate-400'
            }`}
          >
            <Layers className="w-4 h-4" /> تقرير تجميعي
          </button>
          <button
            onClick={() => setReportType('detailed')}
            className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-sm font-bold transition-all ${
              reportType === 'detailed' ? 'bg-emerald-500 text-white shadow-lg shadow-emerald-500/30' : 'text-slate-500 dark:text-slate-400'
            }`}
          >
            <List className="w-4 h-4" /> تقرير تفصيلي
          </button>
        </div>

        <div className="flex gap-3">
          <button 
            onClick={exportCSV}
            className="flex items-center gap-2 text-sm text-emerald-700 dark:text-emerald-400 border border-emerald-100 dark:border-emerald-900/30 bg-emerald-50 dark:bg-emerald-900/20 px-4 py-2 rounded-xl hover:bg-emerald-100 dark:hover:bg-emerald-900/40 transition-colors font-bold"
          >
            <FileSpreadsheet className="w-4 h-4" /> تصدير CSV
          </button>
          <button 
            onClick={exportPDF}
            className="flex items-center gap-2 text-sm text-slate-700 dark:text-slate-300 border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 px-4 py-2 rounded-xl hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors font-bold"
          >
            <Printer className="w-4 h-4" /> تصدير PDF / طباعة
          </button>
        </div>
      </div>

      {reportType === 'aggregated' ? (
        <div className="bg-white dark:bg-slate-900 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-800 overflow-hidden print:border-none transition-colors">
          <div className="p-6 border-b border-slate-100 dark:border-slate-800 bg-slate-50 dark:bg-slate-800/50 print:bg-white flex justify-between items-center">
            <div>
              <h3 className="font-bold text-slate-800 dark:text-white">إجمالي استهلاك الخامات</h3>
              <p className="text-xs text-slate-500 dark:text-slate-400">مجمع بناءً على الوصفات والمبيعات للفترة المحددة</p>
            </div>
            <div className="text-left text-xs font-mono text-slate-400">
              {startDate} ⮕ {endDate}
            </div>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-right">
              <thead className="bg-slate-50/50 dark:bg-slate-800/20">
                <tr>
                  <th className="px-6 py-4 font-semibold text-slate-600 dark:text-slate-400">الخامة</th>
                  <th className="px-6 py-4 font-semibold text-slate-600 dark:text-slate-400">وحدة القياس</th>
                  <th className="px-6 py-4 font-semibold text-slate-600 dark:text-slate-400 text-left">إجمالي الاستهلاك</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                {aggregatedData.length > 0 ? aggregatedData.map((data, i) => (
                  <tr key={i} className="hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors">
                    <td className="px-6 py-4 font-bold text-slate-700 dark:text-slate-200">{data.name}</td>
                    <td className="px-6 py-4 text-slate-500 dark:text-slate-400">{data.unit}</td>
                    <td className="px-6 py-4 font-mono font-bold text-emerald-600 dark:text-emerald-400 text-left">
                      {data.total.toLocaleString(undefined, { minimumFractionDigits: 3 })}
                    </td>
                  </tr>
                )) : (
                  <tr>
                    <td colSpan={3} className="px-6 py-12 text-center text-slate-400 dark:text-slate-600 italic">لا توجد بيانات مبيعات في هذه الفترة لحساب الاستهلاك</td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      ) : (
        <div className="space-y-6">
          {detailedData.length > 0 ? detailedData.map((item, idx) => (
            <div key={idx} className="bg-white dark:bg-slate-900 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-800 overflow-hidden print:break-inside-avoid transition-colors">
              <div className="p-4 bg-slate-900 dark:bg-slate-800 text-white flex justify-between items-center print:bg-slate-100 print:text-slate-900 print:border-b">
                <span className="text-lg font-bold">{item.itemName}</span>
                <span className="bg-emerald-500 px-3 py-1 rounded-lg text-sm font-bold print:bg-slate-200">المباع: {item.quantitySold} وحدة</span>
              </div>
              <div className="overflow-x-auto">
                <table className="w-full text-right">
                  <thead className="bg-slate-50 dark:bg-slate-800/50 border-b border-slate-100 dark:border-slate-800">
                    <tr>
                      <th className="px-6 py-3 text-xs font-bold text-slate-400 uppercase">الخامة</th>
                      <th className="px-6 py-3 text-xs font-bold text-slate-400 uppercase text-left">كمية الاستهلاك</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-50 dark:divide-slate-800">
                    {item.ingredients.map((ing, iIdx) => (
                      <tr key={iIdx} className="hover:bg-slate-50/50 dark:hover:bg-slate-800/30">
                        <td className="px-6 py-3 text-sm text-slate-600 dark:text-slate-400">{ing.materialName}</td>
                        <td className="px-6 py-3 text-sm font-mono font-bold text-slate-800 dark:text-slate-200 text-left">
                          {ing.consumedQuantity.toLocaleString(undefined, { minimumFractionDigits: 3 })} {ing.unit}
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )) : (
            <div className="bg-white dark:bg-slate-900 p-12 text-center text-slate-400 dark:text-slate-600 rounded-2xl border border-slate-200 dark:border-slate-800 transition-colors">
              لا توجد مبيعات تفصيلية لعرضها في الفترة المختارة.
            </div>
          )}
        </div>
      )}

      {/* Print Footer */}
      <div className="hidden print:block mt-8 text-center text-[10px] text-slate-400 border-t pt-4">
        هذا التقرير تم إنشاؤه آلياً بواسطة نظام CulinaTrack - الفترة المشمولة: {startDate} إلى {endDate}
      </div>
    </div>
  );
};

export default ReportsPage;

import React, { useState } from 'react';
import { Plus, Trash2, Scale, AlertCircle, Edit3, Save, X } from 'lucide-react';
import { Unit } from '../types';

interface Props {
  units: Unit[];
  onAdd: (u: Unit) => Promise<void>;
  onUpdate: (u: Unit) => Promise<void>;
  onDelete: (id: string) => Promise<void>;
}

const UnitsPage: React.FC<Props> = ({ units, onAdd, onUpdate, onDelete }) => {
  const [name, setName] = useState('');
  const [error, setError] = useState('');

  const [editingId, setEditingId] = useState<string | null>(null);
  const [editName, setEditName] = useState('');
  const [editError, setEditError] = useState('');

  const addUnit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    if (!name.trim()) return setError('يرجى إدخال اسم الوحدة');
    if (units.some(u => u.name.trim() === name.trim())) 
      return setError('هذه الوحدة موجودة بالفعل');

    const newUnit: Unit = { id: crypto.randomUUID(), name: name.trim() };
    await onAdd(newUnit);
    setName('');
  };

  const saveEdit = async (id: string) => {
    setEditError('');
    if (!editName.trim()) return setEditError('الاسم مطلوب');
    if (units.some(u => u.id !== id && u.name.trim() === editName.trim()))
      return setEditError('هذا الاسم مستخدم لوحدة أخرى');

    await onUpdate({ id, name: editName.trim() });
    setEditingId(null);
  };

  const handleDelete = async (id: string, name: string) => {
    if (window.confirm(`هل أنت متأكد من حذف وحدة القياس "${name}"؟ سيؤثر ذلك على عرض الوحدات في الخامات المربوطة بها.`)) {
      await onDelete(id);
    }
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6">
      <div className="bg-white dark:bg-slate-900 p-6 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-800 transition-colors">
        <h3 className="text-lg font-semibold mb-4 flex items-center gap-2 dark:text-white">
          <Plus className="w-5 h-5 text-emerald-500" /> إضافة وحدة قياس جديدة
        </h3>
        <form onSubmit={addUnit} className="flex gap-4">
          <div className="flex-1">
            <input
              type="text" placeholder="اسم الوحدة (مثال: ملعقة كبيرة)"
              className={`w-full border ${error ? 'border-rose-500' : 'border-slate-200 dark:border-slate-700'} bg-white dark:bg-slate-800 dark:text-white rounded-xl px-4 py-2 outline-none focus:ring-2 focus:ring-emerald-500 transition-all`}
              value={name} onChange={(e) => { setName(e.target.value); if (error) setError(''); }}
            />
            {error && <p className="text-rose-500 text-xs mt-1 flex items-center gap-1"><AlertCircle className="w-3 h-3" /> {error}</p>}
          </div>
          <button className="bg-emerald-500 text-white px-6 py-2 rounded-xl hover:bg-emerald-600 font-bold h-fit transition-transform active:scale-95">إضافة</button>
        </form>
      </div>

      <div className="bg-white dark:bg-slate-900 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-800 overflow-hidden transition-colors">
        <div className="overflow-x-auto">
          <table className="w-full text-right">
            <thead className="bg-slate-50 dark:bg-slate-800/50 border-b border-slate-200 dark:border-slate-800 text-slate-600 dark:text-slate-400">
              <tr><th className="px-6 py-4 font-semibold">اسم الوحدة</th><th className="px-6 py-4 font-semibold w-32">إجراءات</th></tr>
            </thead>
            <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
              {units.map((u) => (
                <tr key={u.id} className="hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors">
                  {editingId === u.id ? (
                    <>
                      <td className="px-6 py-3">
                        <div className="space-y-1">
                          <input 
                            type="text" 
                            className={`w-full border ${editError ? 'border-rose-500' : 'border-slate-200 dark:border-slate-700'} bg-white dark:bg-slate-800 dark:text-white rounded-lg px-3 py-1 outline-none focus:ring-2 focus:ring-emerald-500`} 
                            value={editName} 
                            onChange={(e) => setEditName(e.target.value)} 
                            autoFocus 
                          />
                          {editError && <p className="text-rose-500 text-[10px]">{editError}</p>}
                        </div>
                      </td>
                      <td className="px-6 py-3 flex gap-2">
                        <button onClick={() => saveEdit(u.id)} className="p-1.5 text-emerald-600 hover:bg-emerald-50 dark:hover:bg-emerald-900/20 rounded-lg"><Save className="w-4 h-4" /></button>
                        <button onClick={() => setEditingId(null)} className="p-1.5 text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-lg"><X className="w-4 h-4" /></button>
                      </td>
                    </>
                  ) : (
                    <>
                      <td className="px-6 py-4 flex items-center gap-3 dark:text-slate-200"><Scale className="w-4 h-4 text-slate-400" />{u.name}</td>
                      <td className="px-6 py-4 flex gap-1">
                        <button onClick={() => { setEditingId(u.id); setEditName(u.name); setEditError(''); }} className="p-2 text-blue-500 dark:text-blue-400 hover:bg-blue-50 dark:hover:bg-blue-900/20 rounded-lg" title="تعديل"><Edit3 className="w-4 h-4" /></button>
                        <button onClick={() => handleDelete(u.id, u.name)} className="p-2 text-rose-500 dark:text-rose-400 hover:bg-rose-50 dark:hover:bg-rose-900/20 rounded-lg" title="حذف"><Trash2 className="w-4 h-4" /></button>
                      </td>
                    </>
                  )}
                </tr>
              ))}
              {units.length === 0 && (
                <tr>
                  <td colSpan={2} className="px-6 py-8 text-center text-slate-400 dark:text-slate-600 italic">لا توجد وحدات مضافة</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default UnitsPage;

import React, { useState, useEffect } from 'react';
import { Plus, Trash2, Calculator, AlertCircle, Save } from 'lucide-react';
import { SalesItem, Material, Recipe, RecipeIngredient } from '../types';

interface Props {
  items: SalesItem[];
  materials: Material[];
  recipes: Recipe[];
  onSave: (recipe: Recipe) => Promise<void>;
}

const RecipeBuilderPage: React.FC<Props> = ({ items, materials, recipes, onSave }) => {
  const [selectedItemId, setSelectedItemId] = useState<string>('');
  const [localIngredients, setLocalIngredients] = useState<RecipeIngredient[]>([]);
  const [isSaving, setIsSaving] = useState(false);

  useEffect(() => {
    const existing = recipes.find(r => r.itemId === selectedItemId);
    setLocalIngredients(existing ? [...existing.ingredients] : []);
  }, [selectedItemId, recipes]);

  const addIngredient = () => {
    if (!selectedItemId || materials.length === 0) return;
    setLocalIngredients([...localIngredients, { materialId: materials[0].id, quantity: 0 }]);
  };

  const updateIngredient = (idx: number, field: keyof RecipeIngredient, value: string | number) => {
    const next = [...localIngredients];
    if (field === 'quantity') next[idx].quantity = parseFloat(String(value)) || 0;
    else next[idx].materialId = String(value);
    setLocalIngredients(next);
  };

  const removeIngredient = (idx: number) => {
    setLocalIngredients(localIngredients.filter((_, i) => i !== idx));
  };

  const handleSave = async () => {
    setIsSaving(true);
    await onSave({ itemId: selectedItemId, ingredients: localIngredients });
    setIsSaving(false);
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6">
      <div className="bg-white dark:bg-slate-900 p-6 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-800 transition-colors">
        <label className="block text-sm font-semibold text-slate-700 dark:text-slate-300 mb-2">اختر صنف المبيعات لتعديل وصفته:</label>
        <select
          className="w-full border border-slate-200 dark:border-slate-700 rounded-xl px-4 py-3 bg-white dark:bg-slate-800 dark:text-white outline-none focus:ring-2 focus:ring-emerald-500 font-medium transition-colors"
          value={selectedItemId} onChange={(e) => setSelectedItemId(e.target.value)}
        >
          <option value="">-- اختر صنفاً --</option>
          {items.map(i => <option key={i.id} value={i.id}>{i.name}</option>)}
        </select>
      </div>

      {selectedItemId && (
        <div className="bg-white dark:bg-slate-900 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-800 overflow-hidden animate-in fade-in slide-in-from-bottom-2 transition-colors">
          <div className="p-6 border-b border-slate-100 dark:border-slate-800 flex justify-between items-center bg-slate-50/50 dark:bg-slate-800/50">
            <h3 className="font-bold text-slate-800 dark:text-white">وصفة: <span className="text-emerald-600 dark:text-emerald-400">{items.find(i => i.id === selectedItemId)?.name}</span></h3>
            <div className="flex gap-2">
               <button onClick={addIngredient} className="flex items-center gap-2 text-sm bg-slate-800 dark:bg-slate-700 text-white px-4 py-2 rounded-xl font-bold hover:bg-slate-700 transition-colors"><Plus className="w-4 h-4" /> إضافة خامة</button>
               <button onClick={handleSave} disabled={isSaving} className="flex items-center gap-2 text-sm bg-emerald-500 text-white px-6 py-2 rounded-xl font-bold shadow-lg shadow-emerald-500/20 disabled:bg-slate-300 dark:disabled:bg-slate-800 transition-all hover:scale-105 active:scale-95"><Save className="w-4 h-4" /> {isSaving ? 'جاري الحفظ...' : 'حفظ الوصفة'}</button>
            </div>
          </div>
          <div className="p-6 space-y-4">
            {localIngredients.length === 0 ? (
              <div className="text-center py-12 text-slate-400 dark:text-slate-600"><Calculator className="w-12 h-12 mx-auto mb-3 opacity-20" /><p>لا توجد خامات مضافة لهذه الوصفة بعد.</p></div>
            ) : (
              localIngredients.map((ing, idx) => (
                <div key={idx} className="flex flex-col md:flex-row gap-4 items-start bg-slate-50/50 dark:bg-slate-800/30 p-4 rounded-xl border border-slate-100 dark:border-slate-800/50">
                  <div className="flex-1 w-full">
                    <label className="block text-xs font-bold text-slate-500 dark:text-slate-500 mb-1 mr-1">الخامة</label>
                    <select className="w-full border border-slate-200 dark:border-slate-700 rounded-xl px-4 py-2 bg-white dark:bg-slate-800 dark:text-white outline-none focus:ring-2 focus:ring-emerald-500 transition-colors" value={ing.materialId} onChange={(e) => updateIngredient(idx, 'materialId', e.target.value)}>
                      {materials.map(m => <option key={m.id} value={m.id}>{m.name} ({m.unit})</option>)}
                    </select>
                  </div>
                  <div className="w-full md:w-48">
                    <label className="block text-xs font-bold text-slate-500 dark:text-slate-500 mb-1 mr-1">الكمية لكل وحدة مباعة</label>
                    <input type="number" step="0.001" className="w-full border border-slate-200 dark:border-slate-700 rounded-xl px-4 py-2 outline-none focus:ring-2 focus:ring-emerald-500 bg-white dark:bg-slate-800 dark:text-white font-mono font-bold transition-colors" value={ing.quantity || ''} onChange={(e) => updateIngredient(idx, 'quantity', e.target.value)} />
                  </div>
                  <button onClick={() => removeIngredient(idx)} className="p-2.5 text-rose-500 hover:bg-rose-50 dark:hover:bg-rose-900/20 rounded-xl md:mt-5 self-end"><Trash2 className="w-5 h-5" /></button>
                </div>
              ))
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default RecipeBuilderPage;
